head.script:
scwin.MSG_SD_WRN_001 = "통합매출 정보를 생성해야 합니다.";
scwin.MSG_SD_WRN_002 = "출고예정 시간이 형식에 일치하지 않습니다.";
scwin.MSG_SD_WRN_003 = "출고예정 분이 형식에 일치하지 않습니다.";
scwin.MSG_SD_WRN_004 = "확정된 것은 삭제할 수 없습니다.";
scwin.MSG_SD_WRN_005 = "항목을 먼저 선택해야 합니다.";
scwin.MSG_SD_WRN_006 = "확정인 경우 삭제할수 없습니다.";
scwin.MSG_SD_WRN_007 = "오더번호가 다를 경우 삭제할수 없습니다.";
scwin.MSG_SD_WRN_008 = "매출항목 조회결과가 없습니다.";
scwin.MSG_SD_WRN_009 = "원본 데이타가 존재하지 않습니다.";
scwin.MSG_SD_WRN_010 = "분할된 금액이 존재할 경우 삭제할수 없습니다.";
scwin.MSG_SD_WRN_011 = "저장된 상태에서만 금액분할이 가능합니다.";
scwin.MSG_SD_WRN_012 = "분할 금액이 원금액을 초과할수 없습니다.";
scwin.MSG_SD_WRN_013 = "분할 단가가 원단가를 초과할수 없습니다.";
scwin.MSG_SD_WRN_014 = "확정된 것은 금액분할 할수 없습니다.";
scwin.MSG_SD_WRN_015 = "원본 데이타만 금액분할이 가능합니다.";
scwin.MSG_SD_WRN_016 = "저장되지 않은 분할금액이 존재합니다.";
scwin.MSG_SD_WRN_017 = "오더 컨테이너 목록에 존재하지 않는 순번 입니다.";
scwin.MSG_SD_WRN_018 = "출고예정번호가 존재하지 않습니다.";
scwin.MSG_SD_WRN_019 = "실적매출은 삭제할수 없습니다.";
scwin.MSG_SD_WRN_020 = "출고예정번호가 다른 것은 삭제할 수 없습니다.";

scwin.selectedKey = null;	// 선택된 행의 key값

// ===== 화면 입력 파라미터 =====
scwin.odrNo = "";	// 오더번호: 조회 조건으로 사용되는 오더번호
scwin.outIntendNo = ""; 	// 출고예정번호: 조회 조건으로 사용되는 출고예정번호


// ===== 화면 동작 제어 변수 =====
scwin.delflag = '';                  // 삭제 플래그: 삭제 처리 시 'DEL'로 설정
scwin.sellItemCd = '';                  // 선택된 매출항목 코드
scwin.commSeq = 0;                   // 선택된 순번
scwin.closeFlag = '';                  // 닫기 플래그
scwin.fitRow = 0;                   // 금액분할 시 원본 행 번호
scwin.addYn = "N";                 // 추가 모드 여부 (Y:추가모드, N:일반모드)
scwin.prevRow = 0;                   // 이전 행 번호 (저장 후 위치 복원용)

// ===== 청구 관련 변수 =====
scwin.v_bilgLodeptCd = "";                // 청구부서코드: 매출항목 조회 시 사용
scwin.v_fmlaClsCd = "";                // 청구구분코드: 선청구(01), 후청구(02) 등
scwin.v_fmlaPatternCd = "";                // 청구유형코드: 청구서 서식 유형

// ===== 로그인 사용자 정보 =====
scwin.loabranCd = $c.data.getMemInfo("loabranCd");
scwin.userId = $c.data.getMemInfo("userId");

scwin.Wt20E = 0;
scwin.Wt20F = 0;
scwin.Wt40E = 0;
scwin.Wt40F = 0;
scwin.Wt45E = 0;
scwin.Wt45F = 0;

scwin._odrDcsnYn = "";
scwin._bondMcom = "";

scwin.strCurDate = "";
scwin.strCurDate2 = "";
scwin.currentTime = "";


// 서버에서 조회해온 전역변수
scwin.elecReceiptExcept = "";	//CY후불거래처의 전자수납 제외gr_txn
scwin.deptInfo = "";			//청구부서의 점소
scwin.responseTypeInfo = "";	//응답여부
scwin.responseTypeInfo2 = "";	//응답여부2

scwin.onpageload = async function () {
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.strCurDate2 = $c.date.addDate(scwin.strCurDate, 7);

    let now = new Date();
    let hof = now.getHours().toString();
    let mm = now.getMinutes().toString();
    if (hof.length == 1) { hof = "0" + hof; }
    if (mm.length == 1) { mm = "0" + mm; }
    scwin.currentTime = hof + mm;

    let param = $c.data.getParameter();
    scwin.odrNo = param.odrNo ?? ""
    scwin.outIntendNo = param.outIntendNo ?? "";

    const codeOptions = [
        { grpCd: "SD227", compID: "acb_responsetype" },
        { grpCd: "CO028", compID: "gr_unitySelling:dcScCd" },
        { grpCd: "ZZ006", compID: "gr_unitySelling:crcCd" }
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.f_RetrieveSellUnitCd();

    //TestData
    //ed_outIntendNoSearch.setValue("0001189340");
};

scwin.onUdcCompleted = async function () {
    rd_prebilgClsCd.setValue("02");
    acb_outAdjmPatternCd.setValue("06");

    ica_outIntendDt.setValue(scwin.strCurDate);
    ed_outIntendHh.setValue(scwin.currentTime);
    ica_rsltsStdDt.setValue(scwin.strCurDate);

    ed_Wt20E.setValue(0);
    ed_Wt20F.setValue(0);
    ed_Wt40E.setValue(0);
    ed_Wt40F.setValue(0);
    ed_Wt45E.setValue(0);
    ed_Wt45F.setValue(0);

    if (scwin.odrNo != "") {
        ed_outIntendNoSearch.setValue(scwin.outIntendNo);
        ed_odrNo.setValue(scwin.odrNo);

        scwin.f_Retrieve("Conn");
    }

    if (scwin.loabranCd == "4BB" || scwin.loabranCd == "6AA") {
        //추가버튼 보이기
        btn_create.show();
    }
    else {
        //추가버튼 숨기기
        btn_create.hide();
    }

};

scwin.f_Retrieve = async function (selFg) {
    dma_odrOutIntend_con.set("odrNo", "");
    dma_odrOutIntend_con.set("outIntendNo", "");

    if (selFg == "Conn") {
        dma_odrOutIntend_con.set("odrNo", ed_odrNo.getValue() ?? "");
        dma_odrOutIntend_con.set("outIntendNo", ed_outIntendNoSearch.getValue());
    } else if (selFg == "Enter") {
        dma_odrOutIntend_con.set("odrNo", ed_odrNo.getValue() ?? "");
        dma_odrOutIntend_con.set("outIntendNo", "");
    } else if (selFg == "Button") {
        let chk = await $c.gus.cfValidate([ed_outIntendNoSearch], null, true);
        if (!chk) {
            return;
        }
        dma_odrOutIntend_con.set("odrNo", "");
        dma_odrOutIntend_con.set("outIntendNo", ed_outIntendNoSearch.getValue());
    }

    await $c.sbm.execute(sbm_cntrOutIntend_retrieve);
};

scwin.f_Create = async function () {
    $c.gus.cfInitObjects(grp_search, [ed_odrNo]);

    ed_odrNo.setReadOnly(false);
    btn_ordNo.setDisabled(false);

    ds_cntrBulkOutIntend.removeAll();
    ds_cntrBulkOutIntendDetail.removeAll();
    ds_unitySelling.removeAll();

    ed_odrNo.focus();

    if (rd_prebilgClsCd.getValue() == "01") {	// 01: 선청구
        ed_fmlaPatternNm.hide();				// 일반 청구유형 숨김
        acb_fmlaPatternCd.show();				// 선청구 유형 표시
    } else {									// 02: 선수납(후청구)
        ed_fmlaPatternNm.show();				// 일반 청구유형 표시
        acb_fmlaPatternCd.hide();				// 선청구 유형 숨김
    }

};

scwin.f_add = function () {
    scwin.addYn = "Y";  // 추가 모드 ON

    // 매출 데이터의 변경사항 모두 취소
    ds_unitySelling.undoAll();

    // 금액 필드 초기화
    ed_spplyAmt.setValue(0);  // 공급가액 0으로 초기화
    ed_vatAmt.setValue(0);    // 부가세 0으로 초기화

};

scwin.f_Save = async function () {
    let chk1 = await $c.gus.cfValidate([ed_bilgLodeptCd, ed_bilgClntNo, ica_rsltsStdDt, ica_outIntendDt, ed_outIntendHh, ed_sellLodeptCd], null, true);
    if (!chk1) {
        return;
    }

    //ed_outIntendHh 값이 HHmm 인지 확인한다.
    let outIntendHh = ed_outIntendHh.getValue();
    if (!/^\d{4}$/.test(outIntendHh)) {	//숫자 4자리인지 확인
        await $c.win.alert("출고예정일시가 올바르지 않습니다.");
        ed_outIntendHh.focus();
        return;
    }
    let outIntendHhHour = outIntendHh.substr(0, 2);	//시
    let outIntendHhMinute = outIntendHh.substr(2, 2);	//분
    if (outIntendHhHour < 0 || outIntendHhHour > 23) {
        await $c.win.alert("출고예정일시가 올바르지 않습니다.");
        ed_outIntendHh.focus();
        return;
    }
    if (outIntendHhMinute < 0 || outIntendHhMinute > 59) {
        await $c.win.alert("출고예정일시가 올바르지 않습니다.");
        ed_outIntendHh.focus();
        return;
    }

    //CY후불거래처의 전자수납 제외 LIST 조회
    await scwin.f_setElecReceiptExceptList();

    //청구부서의 점소 조회 
    await scwin.f_setDeptInfo();

    //현 응답여부 조회
    await scwin.f_setResponseTypeInfo();

    let cntrBulkOutIntendDetailValidation = await $c.gus.cfValidate([gr_cntrBulkOutIntendDetail], null, true);
    if (!cntrBulkOutIntendDetailValidation) {
        return;
    }

    let unitySellingValidation = await $c.gus.cfValidate([gr_unitySelling], null, true);
    if (!unitySellingValidation) {
        return;
    }

    for (let i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
        if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") == "") {
                await $c.win.alert("오더 컨테이너 목록의 " + (i + 1) + "번째 출고예정일자는 필수항목입니다.");
                ds_cntrBulkOutIntendDetail.setRowPosition(i);
                gr_cntrBulkOutIntendDetail.setFocusedCell(i, "outIntendDt");
                return;
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendHh") == "") {
                await $c.win.alert("오더 컨테이너 목록의 " + (i + 1) + "번째 출고예정시분은 필수항목입니다.");
                ds_cntrBulkOutIntendDetail.setRowPosition(i);
                gr_cntrBulkOutIntendDetail.setFocusedCell(i, "outIntendHh");
                return;
            }
        }
    }

    ds_cntrBulkOutIntend.setCellData(0, "outIntendNo", ed_outIntendNo.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "prebilgClsCd", rd_prebilgClsCd.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "bilgLodeptCd", ed_bilgLodeptCd.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "sellLodeptCd", ed_sellLodeptCd.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "bilgClntNo", ed_bilgClntNo.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "depositClntNo", ed_depositClntNo.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "pldgClntNo", ed_pldgClntNo.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "outIntendDt", ica_outIntendDt.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "outIntendHh", ed_outIntendHh.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "outAdjmPatternCd", acb_outAdjmPatternCd.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "summary", ed_summary.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "jdgAmt", ed_jdgAmt.getValue());
    ds_cntrBulkOutIntend.setCellData(0, "cstmdtAmt", ed_cstmdtAmt.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "spplyAmt", ed_spplyAmt.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "vatAmt", ed_vatAmt.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "issudcRmk", ed_issudcRmk.getValue() ?? "");
    ds_cntrBulkOutIntend.setCellData(0, "issudcExpireDt", ica_issudcExpireDt.getValue() ?? "");


    let maxAdptExchRt = undefined;
    let maxAdptExchRtDt = undefined;

    let unitySellingCount = ds_unitySelling.getRowCount();
    for (let i = 0; i < unitySellingCount; i++) {
        let adptExchRt = ds_unitySelling.getCellData(i, 'adptExchRt');
        let adptExchRtDt = ds_unitySelling.getCellData(i, 'adptExchRtDt');

        if (maxAdptExchRt === undefined || maxAdptExchRt < adptExchRt) {
            maxAdptExchRt = adptExchRt;
        }
        if (maxAdptExchRtDt === undefined || maxAdptExchRtDt < adptExchRtDt) {
            maxAdptExchRtDt = adptExchRtDt;
        }
    }

    let adptExchRt = ds_cntrBulkOutIntend.getCellData(0, "adptExchRt");
    if (adptExchRt <= 0) {
        ds_cntrBulkOutIntend.setCellData(0, "adptExchRt", maxAdptExchRt);
        ds_cntrBulkOutIntend.setCellData(0, "adptExchRtDt", maxAdptExchRtDt);
    }

    ds_cntrBulkOutIntend.setCellData(0, "fmlaClsCd", scwin.v_fmlaClsCd);
    ds_cntrBulkOutIntend.setCellData(0, "fmlaPatternCd", scwin.v_fmlaPatternCd);

    for (let i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
        if (ds_cntrBulkOutIntend.getCellData(0, "cntrYn") == "1") {
            ds_cntrBulkOutIntendDetail.setCellData(i, "qtyUnitCd", "VAN");
        } else {
            ds_cntrBulkOutIntendDetail.setCellData(i, "qtyUnitCd", "");
        }
    }

    scwin.f_ChkData();

    // TODO : Server로 변경되지 않은 Data를 보내는 기능 여부 라는데 이게 어떤 영향을 미칠것인지 확인 필요
    // ds_cntrBulkOutIntend.UseChangeInfo = "false";
    // ds_cntrBulkOutIntendDetail.UseChangeInfo = "false";   		
    // ds_unitySelling.UseChangeInfo = "true";   	

    for (let k = 0; k < ds_unitySelling.getRowCount(); k++) {
        if (ds_unitySelling.getCellData(k, "choice") == "T") {
            // 2013.11.27 hurrah015 KBCTCY경우 매출입항목이 식물검역료,구내셔틀료,세관검사료
            // 인경우 운송부서에서 이 화면을 거래할때 매출부서가 운송부서로 바뀌는 현상 개선
            ds_unitySelling.setCellData(k, "bilgClntNo", ed_bilgClntNo.getValue() ?? "");	// 청구거래처코드
            ds_unitySelling.setCellData(k, "bilgLodeptCd", ed_bilgLodeptCd.getValue() ?? "");// 청구부서코드

            if (scwin.addYn == "Y") {
                if (ds_unitySelling.getRowStatus(k) == "C" || ds_unitySelling.getRowStatus(k) == "D") {	//insert or delete
                    ds_unitySelling.setCellData(k, "bilgClntNo", ed_bilgClntNo.getValue() ?? "");	// 청구거래처코드
                    ds_unitySelling.setCellData(k, "bilgLodeptCd", ed_bilgLodeptCd.getValue() ?? "");// 청구부서코드
                }
            }
            else {
                ds_unitySelling.setCellData(k, "bilgClntNo", ed_bilgClntNo.getValue() ?? "");	// 청구거래처코드
                ds_unitySelling.setCellData(k, "bilgLodeptCd", ed_bilgLodeptCd.getValue() ?? "");// 청구부서코드
            }

            if (ed_dptWrkPlNm.getValue() == "KBCTCY") {
                if (ds_unitySelling.getCellData(k, "sellItemCd") != "0160"		// 식물검역료
                    && ds_unitySelling.getCellData(k, "sellItemCd") != "1200"		// 구내셔틀료
                    && ds_unitySelling.getCellData(k, "sellItemCd") != "0028") {		// 세관검사료

                    ds_unitySelling.setCellData(k, "sellLodeptCd", ed_sellLodeptCd.getValue() ?? "");	// 매출부서코드
                }
            }
            else {
                ds_unitySelling.setCellData(k, "sellLodeptCd", ed_sellLodeptCd.getValue() ?? "");	// 매출부서코드
            }
        }

        if (ds_unitySelling.getCellData(k, "volAmtDivsClsCd") == "C") {
            ds_unitySelling.setCellData(k, "volAmtDivsClsCd", "A");
        }

        ds_unitySelling.setCellData(k, "dcScCd", ds_unitySelling.getCellData(k, "dcScCd").trim());
    }


    if (ed_outIntendNo.getValue() == "") {	// 신규 : 출고예정번호가 없을때
        ds_cntrBulkOutIntend.setCellData(0, "outAdjmStsCd", "01");
        scwin.prevRow = ds_unitySelling.getRowPosition();

        let newConfirm = await $c.win.confirm(MSG_CM_CRM_001);
        if (!newConfirm)
            return;

        await $c.sbm.execute(sbm_cntrOutIntend_save);
    } else {	//수정 : 출고예정번호가 있을때 

        if (!scwin.f_elecReceiptCntl("U"))
            return;

        let otherCnt = 0;
        for (let j = 0; j < ds_unitySelling.getRowCount(); j++) {
            if (ds_unitySelling.getRowStatus(j) != "D") {
                if (ds_unitySelling.getCellData(scwin.fitRow, "odrNo") == ds_unitySelling.getCellData(j, "bilgTrgtOdrNo")) {
                    otherCnt++;
                }
            }
            if (otherCnt == 0) {
                ds_unitySelling.setCellData(scwin.fitRow, "volAmtDivsClsCd", "N");
            }
        }

        scwin.prevRow = ds_unitySelling.getRowPosition();

        if (scwin.responseTypeInfo == "L") {
            if (ds_cntrBulkOutIntend.getCellData(0, "bilgClntNo") == ds_cntrBulkOutIntend.getOriginalCellData(1, "bilgClntNo")) {
                $c.win.alert("전자수납 응답여부가 승인인 경우 청구거래처만 수정 가능합니다.");
                return false;
            }

            if (ds_cntrBulkOutIntendDetail.isUpdated == true) {
                $c.win.alert("오더 컨테이너 목록은 수정 불가 합니다.")
                return false;
            }

            if (ds_unitySelling.isUpdated == true) {
                if (ds_unitySelling.getCellData(1, "bilgClntNo") == ds_unitySelling.getOriginalCellData(1, "bilgClntNo")) {
                    $c.win.alert("전자수납 응답여부가 승인인 경우 청구거래처만 수정 가능합니다.");
                    return false;
                }
            }
        }

        let updateConfirm = await $c.win.confirm(MSG_CM_CRM_001);
        if (!updateConfirm)
            return;

        await $c.sbm.execute(sbm_cntrOutIntend_update);
    }
};

scwin.f_ChkData = async function () {
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (rd_prebilgClsCd.getValue() == "02") {
            if (ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd") == "05") {
                if (acb_outAdjmPatternCd.getValue() == "04") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "N");
                    ds_unitySelling.setCellData(i, "outIntendSeq", 0);
                } else if (acb_outAdjmPatternCd.getValue() == "06") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
                    ds_unitySelling.setCellData(i, "outIntendSeq", 0);
                } else if (acb_outAdjmPatternCd.getValue() == "05") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
                } else if (acb_outAdjmPatternCd.getValue() == "09") {
                    ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
                }
            } else {
                ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
            }
        } else {
            ds_cntrBulkOutIntendDetail.setCellData(0, "createClsCd", "Y");
        }
    }
};

scwin.f_SumAmt = async function () {
    let sellAmt = 0;	// 공급가액 합계
    let vatAmt = 0;		// 부가세 합계

    // 모든 매출항목 행을 순회하며 금액 합계
    let rowCount = ds_unitySelling.getRowCount();
    for (let i = 0; i < rowCount; i++) {

        // 선택되었고(choice='T') 삭제되지 않은(상태≠2) 항목만 합계
        if (ds_unitySelling.getCellData(i, "choice") == "T" && ds_unitySelling.getRowStatus(i) != "D") {
            sellAmt = sellAmt + Number(ds_unitySelling.getCellData(i, "sellAmt"));
            vatAmt = vatAmt + Number(ds_unitySelling.getCellData(i, "vatAmt"));
        }
    }

    // 합계 금액을 화면에 표시
    ed_spplyAmt.setValue(sellAmt);				// 공급가액 합계
    ed_vatAmt.setValue(vatAmt);					// 부가세 합계
    ed_totAmt.setValue(sellAmt + vatAmt);		// 총금액 (공급+부가)
};

scwin.f_AddSumAmt = function () {
    let sellAmt = 0;	// 공급가액 합계
    let vatAmt = 0;   // 부가세 합계

    // 모든 매출항목 행을 순회하며 합계
    let rowCount = ds_unitySelling.getRowCount();
    for (let i = 0; i < rowCount; i++) {
        // 선택되었고(T) 새로추가(1) 또는 수정(3)된 항목만 합계
        if (ds_unitySelling.getCellData(i, "choice") == "T" && (ds_unitySelling.getRowStatus(i) == 1 || ds_unitySelling.getRowStatus(i) == "U")) {
            sellAmt = sellAmt + Number(ds_unitySelling.getCellData(i, "sellAmt"));  // 공급가액 누적
            vatAmt = vatAmt + Number(ds_unitySelling.getCellData(i, "vatAmt"));   // 부가세 누적	
        }
    }
    // 합계 금액을 화면에 표시
    ed_spplyAmt.setValue(sellAmt);				// 공급가액 합계
    ed_vatAmt.setValue(vatAmt);					// 부가세 합계
    ed_totAmt.setValue(sellAmt + vatAmt);		// 총금액 (공급+부가)
};

scwin.f_PostSumAmt = async function (i) {
    if (i == 0) {
        scwin.Wt20E = 0; scwin.Wt20F = 0; scwin.Wt40E = 0;
        scwin.Wt40F = 0; scwin.Wt45E = 0; scwin.Wt45F = 0;
    }

    // 선택된 컨테이너만 카운팅
    if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
        let sizCd = ds_cntrBulkOutIntendDetail.getCellData(i, "cntrSizCd");
        let feCls = ds_cntrBulkOutIntendDetail.getCellData(i, "fullEmptyClsCd");
        if (sizCd == "20" && feCls == "E") {	// 20피트 공컨(Empty)
            scwin.Wt20E++;
        }
        else if (sizCd == "20" && feCls == "F") {// 20피트 실컨(Full)
            scwin.Wt20F++;
        }
        else if (sizCd == "40" && feCls == "E") {// 40피트 공컨(Empty)
            scwin.Wt40E++;
        }
        else if (sizCd == "40" && feCls == "F") {// 40피트 실컨(Full)
            scwin.Wt40F++;
        }
        else if (sizCd == "45" && feCls == "E") {// 45피트 공컨(Empty)
            scwin.Wt45E++;
        }
        else if (sizCd == "45" && feCls == "F") {// 45피트 실컨(Full)
            scwin.Wt45F++;
        }
    }

    // 집계된 수량을 화면에 표시
    ed_Wt20E.setValue(scwin.Wt20E);
    ed_Wt20F.setValue(scwin.Wt20F);
    ed_Wt40E.setValue(scwin.Wt40E);
    ed_Wt40F.setValue(scwin.Wt40F);
    ed_Wt45E.setValue(scwin.Wt45E);
    ed_Wt45F.setValue(scwin.Wt45F);
};

scwin.f_Delete = async function () {

    // CY후불거래처의 전자수납 제외 LIST 조회
    await scwin.f_setElecReceiptExceptList();
    // 청구부서의 점소 조회 
    await scwin.f_setDeptInfo();
    // 현재 응답여부 조회
    await scwin.f_setResponseTypeInfo();

    // 출고예정번호 존재 여부 확인
    let outIntendNo = ed_outIntendNo.getValue() ?? "";
    if (outIntendNo == "") {
        await $c.win.alert("삭제시에는 출고예정번호로 다시 조회한 후, 삭제하시기 바랍니다. ");
        return false;
    }

    // 통합매출 목록에서 확정된 항목 여부 확인
    let unitySellingCount = ds_unitySelling.getRowCount();
    for (let i = 0; i < unitySellingCount; i++) {

        // 출고예정번호가 있고 확정되지 않은 경우만 삭제 가능
        if (ds_unitySelling.getCellData(i, "outIntendNo") != "") {
            if (ds_unitySelling.getCellData(i, "outIntendNo") == outIntendNo
                && ds_unitySelling.getCellData(i, "dcsnClsCd") != "1") {
                await $c.win.alert(scwin.MSG_SD_WRN_004);	// "확정된 것은 삭제할 수 없습니다."
                return;
            }
        }
    }

    // 전자수납 제어 체크 (삭제 가능 여부 확인)
    if (!scwin.f_elecReceiptCntl("D"))
        return;

    let confirmResult = await $c.win.confirm(MSG_CM_CRM_004);
    if (confirmResult == true) {

        //TODO : 삭제된 항목만 전송처리
        scwin.delflag = "DEL";

        await $c.sbm.execute(sbm_cntrOutIntend_delete);
    }
};

scwin.f_AddRow = function () {

    if (ed_odrNo.getValue() == "") {
        return;
    }

    let newRowIndex = 0;

    if (ds_unitySelling.getRowCount() < 1) {
        ds_unitySelling.insertRow();

        let currentRowPosition = ds_cntrBulkOutIntendDetail.getRowPosition();
        if (currentRowPosition == null || currentRowPosition < 0) {
            ds_cntrBulkOutIntendDetail.setRowPosition(0);
            currentRowPosition = 0;
        }

        ds_unitySelling.setCellData(newRowIndex, "choice", "T");
        ds_unitySelling.setCellData(newRowIndex, "sellCommNo", ds_cntrBulkOutIntendDetail.getCellData(currentRowPosition, "cntrNo"));
        ds_unitySelling.setCellData(newRowIndex, "commNm", ds_cntrBulkOutIntendDetail.getCellData(currentRowPosition, "commNm"));
        ds_unitySelling.setCellData(newRowIndex, "odrNo", ds_cntrBulkOutIntend.getCellData(0, "odrNo"));
        ds_unitySelling.setCellData(newRowIndex, "outIntendNo", ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));
        ds_unitySelling.setCellData(newRowIndex, "updateClsCd", "");
        ds_unitySelling.setCellData(newRowIndex, "commSeq", ds_cntrBulkOutIntendDetail.getCellData(currentRowPosition, "commSeq"));
        ds_unitySelling.setCellData(newRowIndex, "sellVol", 1);
        ds_unitySelling.setCellData(newRowIndex, "prebilgYn", 1);
        ds_unitySelling.setCellData(newRowIndex, "prebilgCreatYn", 1);
        ds_unitySelling.setCellData(newRowIndex, "sellSeq", 0);
        ds_unitySelling.setCellData(newRowIndex, "dcsnClsCd", "1");
        ds_unitySelling.setCellData(newRowIndex, "dcsnClsNm", "미확인");
        ds_unitySelling.setCellData(newRowIndex, "addRowYn", "Y");
        ds_unitySelling.setCellData(newRowIndex, "sellUnitCd", "VAN");

        ds_unitySelling.setCellData(newRowIndex, "mrn", ds_cntrBulkOutIntend.getCellData(0, "mrn"));
        ds_unitySelling.setCellData(newRowIndex, "msn", ds_cntrBulkOutIntend.getCellData(0, "msn"));
        ds_unitySelling.setCellData(newRowIndex, "hsn", ds_cntrBulkOutIntend.getCellData(0, "hsn"));
        ds_unitySelling.setCellData(newRowIndex, "bilgLodeptCd", ds_cntrBulkOutIntend.getCellData(0, "bilgLodeptCd"));
        ds_unitySelling.setCellData(newRowIndex, "sellLodeptCd", ds_cntrBulkOutIntend.getCellData(0, "sellLodeptCd"));
        ds_unitySelling.setCellData(newRowIndex, "lineCd", ds_cntrBulkOutIntend.getCellData(0, "lineCd"));
        ds_unitySelling.setCellData(newRowIndex, "wrkStDt", ds_cntrBulkOutIntend.getCellData(0, "odrDt"));
        ds_unitySelling.setCellData(newRowIndex, "bilgClntNo", ds_cntrBulkOutIntend.getCellData(0, "bilgClntNo"));
        ds_unitySelling.setCellData(newRowIndex, "depositClntNo", ds_cntrBulkOutIntend.getCellData(0, "depositClntNo"));
        ds_unitySelling.setCellData(newRowIndex, "ctrtClntNo", ds_cntrBulkOutIntend.getCellData(0, "ctrtClntNo"));
        ds_unitySelling.setCellData(newRowIndex, "reqClntNo", ds_cntrBulkOutIntend.getCellData(0, "reqClntNo"));
        ds_unitySelling.setCellData(newRowIndex, "taxnClsCd", ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd"));
        ds_unitySelling.setCellData(newRowIndex, "odrDt", ds_cntrBulkOutIntend.getCellData(0, "odrDt"));
        ds_unitySelling.setCellData(newRowIndex, "vsslCd", ds_cntrBulkOutIntend.getCellData(0, "vsslCd"));
        ds_unitySelling.setCellData(newRowIndex, "portcnt", ds_cntrBulkOutIntend.getCellData(0, "portcnt"));
        ds_unitySelling.setCellData(newRowIndex, "dptDistrictCd", ds_cntrBulkOutIntend.getCellData(0, "dptDistrictCd"));
        ds_unitySelling.setCellData(newRowIndex, "arvDistrictCd", ds_cntrBulkOutIntend.getCellData(0, "arvDistrictCd"));
        ds_unitySelling.setCellData(newRowIndex, "impExpDomesticClsCd", ds_cntrBulkOutIntend.getCellData(0, "impExpDomesticClsCd"));
        ds_unitySelling.setCellData(newRowIndex, "ctrtNo", ds_cntrBulkOutIntend.getCellData(0, "ctrtNo"));
        ds_unitySelling.setCellData(newRowIndex, "ctrtWrkPathSeq", ds_cntrBulkOutIntend.getCellData(0, "ctrtWrkPathSeq"));
    } else {
        newRowIndex = ds_unitySelling.getRowPosition() + 1;
        ds_unitySelling.insertRow(newRowIndex);

        for (var i = 0; i < ds_unitySelling.getColumnCount(); i++) {
            let pColId = ds_unitySelling.getColumnID(i);
            if (pColId == "dcsnClsCd") {
                ds_unitySelling.setCellData(newRowIndex, "dcsnClsCd", "1");
            } else if (pColId == "dcsnClsNm") {
                ds_unitySelling.setCellData(newRowIndex, "dcsnClsNm", "미확인");
            } else {
                ds_unitySelling.setCellData(newRowIndex, pColId, ds_unitySelling.getCellData(newRowIndex - 1, pColId));
            }
        }

        ds_unitySelling.setCellData(newRowIndex, "choice", "T");
        ds_unitySelling.setCellData(newRowIndex, "sellSeq", 0);
        ds_unitySelling.setCellData(newRowIndex, "addRowYn", "Y");
        ds_unitySelling.setCellData(newRowIndex, "sellAmt", 0);
        ds_unitySelling.setCellData(newRowIndex, "vatAmt", 0);
        ds_unitySelling.setCellData(newRowIndex, "sumSellAmt", 0);
        ds_unitySelling.setCellData(newRowIndex, "prebilgYn", 1);
        ds_unitySelling.setCellData(newRowIndex, "prebilgCreatYn", 1);
        ds_unitySelling.setCellData(newRowIndex, "updateClsCd", "");
        ds_unitySelling.setCellData(newRowIndex, "outIntendNo", "");
        ds_unitySelling.setCellData(newRowIndex, "odrNo", ds_cntrBulkOutIntend.getCellData(0, "odrNo"));
    }

    ds_unitySelling.setRowPosition(newRowIndex);
    gr_unitySelling.setFocusedCell(newRowIndex, 1);

    ed_unitySellingCount.setValue(ds_unitySelling.getRowCount());	// 매출항목 수 화면에 표시

    gr_unitySelling.setHeaderDisabled('choice', false);
    gr_unitySelling.setHeaderValue('choice', false);
    gr_unitySelling.setColumnReadOnly('choice', false);
    gr_unitySelling.setReadOnly("grid", false);
};

scwin.f_DelRow = async function () {
    let rp = ds_unitySelling.getRowPosition();
    if (rp < 0) {
        return;
    }

    if (ds_unitySelling.getCellData(rp, "dcsnClsCd") != "1") {
        await $c.win.alert(scwin.MSG_SD_WRN_006);
        return;
    }
    if (ds_unitySelling.getCellData(rp, "prebilgYn") != "1") {
        await $c.win.alert(scwin.MSG_SD_WRN_019);
        return;
    }
    if (ds_unitySelling.getCellData(rp, "odrNo") != ds_cntrBulkOutIntend.getCellData(0, "odrNo")) {
        await $c.win.alert(scwin.MSG_SD_WRN_007);
        return;
    }
    if (ds_unitySelling.getCellData(rp, "outIntendNo") != "") {
        if (ds_unitySelling.getCellData(rp, "outIntendNo") != ed_outIntendNo.getValue()) {
            await $c.win.alert(scwin.MSG_SD_WRN_020);
            return;
        }
    }

    let divsCls = ds_unitySelling.getCellData(rp, "volAmtDivsClsCd");
    if (divsCls == "A" || divsCls == "C") {
        if (ds_unitySelling.getCellData(rp, "bilgTrgtOdrNo") == "") {
            let isHaveChild = false;
            for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
                if (ds_unitySelling.getCellData(rp, "odrNo") == ds_unitySelling.getCellData(i, "bilgTrgtOdrNo") &&
                    ds_unitySelling.getCellData(rp, "sellSeq") == ds_unitySelling.getCellData(i, "bilgTrgtSellSeq") &&
                    ds_unitySelling.getRowStatus(i) != "D") {
                    isHaveChild = true;
                    break;
                }
            }
            if (isHaveChild) {
                await $c.win.alert(scwin.MSG_SD_WRN_010);
                return;
            }
        } else {
            ds_unitySelling.setCellData(scwin.fitRow, "sellUpr", Number(ds_unitySelling.getCellData(scwin.fitRow, "sellUpr")) + Number(ds_unitySelling.getCellData(rp, "sellUpr")));
            ds_unitySelling.setCellData(scwin.fitRow, "sellAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "sellAmt")) + Number(ds_unitySelling.getCellData(rp, "sellAmt")));
            ds_unitySelling.setCellData(scwin.fitRow, "vatAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "vatAmt")) + Number(ds_unitySelling.getCellData(rp, "vatAmt")));
            ds_unitySelling.setCellData(scwin.fitRow, "sumSellAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "sumSellAmt")) + Number(ds_unitySelling.getCellData(rp, "sumSellAmt")));
        }
    }

    let rowStatus = ds_unitySelling.getRowStatus(rp);
    if(rowStatus == "C") {
        ds_unitySelling.removeRow(rp);
    } else {
        ds_unitySelling.deleteRow(rp);
    }

    scwin.f_SumAmt();
};

scwin.f_AppendSellItem = async function (sellItemCd, commSeq, close) {

    if ((sellItemCd == undefined || sellItemCd == "") && commSeq != 0) {
        if (ds_cntrBulkOutIntendDetail.getCellData(ds_cntrBulkOutIntendDetail.getRowPosition(), "choice") == "F") {
            await $c.win.alert("해당 CNTR-NO를 선택해야 합니다.");
            return;
        }
    }

    let chk = await $c.gus.cfValidate([ica_outIntendDt, ed_outIntendHh], null, true);
    if (!chk) {
        return;
    }

    await scwin.f_RetrieveSellItem(scwin.v_bilgLodeptCd, scwin.v_fmlaClsCd, scwin.v_fmlaPatternCd);

    for (let k = 0; k < ds_cntrBulkOutIntendDetail.getRowCount(); k++) {

        if (close == "TRUE") {
            scwin.closeFlag = "TRUE";
        } else {
            scwin.closeFlag = "FALSE";
        }

        dma_appendSellItem_con.set("outIntendNo", scwin.ed_outIntendNo);
        dma_appendSellItem_con.set("odrNo", ds_cntrBulkOutIntend.getCellData(0, "odrNo"));
        dma_appendSellItem_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue ? ed_bilgLodeptCd.getValue() : "");
        dma_appendSellItem_con.set("fmlaClsCd", scwin.v_fmlaClsCd);
        dma_appendSellItem_con.set("fmlaPatternCd", scwin.v_fmlaPatternCd);
        dma_appendSellItem_con.set("outAdjmPatternCd", acb_outAdjmPatternCd.getValue());
        dma_appendSellItem_con.set("jdgAmt", ed_jdgAmt.getValue());
        dma_appendSellItem_con.set("cstmdtAmt", ed_cstmdtAmt.getValue());

        if ((sellItemCd == undefined || sellItemCd == "") && commSeq == 0) {
            dma_appendSellItem_con.set("sellItemCd", "");
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(k, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(k, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", ds_cntrBulkOutIntendDetail.getCellData(k, "commSeq"));
        } else if ((sellItemCd == undefined || sellItemCd == "") && commSeq != 0) {
            let drp = ds_cntrBulkOutIntendDetail.getRowPosition();
            dma_appendSellItem_con.set("sellItemCd", "CNTR");
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", ds_cntrBulkOutIntendDetail.getCellData(drp, "commSeq"));
        } else {
            let drp = ds_cntrBulkOutIntendDetail.getRowPosition();
            dma_appendSellItem_con.set("sellItemCd", sellItemCd);
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(drp, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", commSeq);
        }

        // 확정된 매출이 있는 경우 오더컨테이너 목록의 출고예정일자가 수정되지 않음
        // 이미 생성된 출고예정일자와 신규로 입력한 신규예정일자를 비교하여 집계할려는 일자보다 작을때 입력한 일자를 DataSet로 Setting
        if (dma_appendSellItem_con.get("outIntendDt") < ica_outIntendDt.getValue()) {
            dma_appendSellItem_con.set("outIntendDt", ica_outIntendDt.getValue());
        }
    }

    await $c.sbm.execute(sbm_appendSellItem_retrieve);
};

