            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(k, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", ds_cntrBulkOutIntendDetail.getCellData(k, "commSeq"));
        } else if ((scwin.sellItemCd == undefined || scwin.sellItemCd == "") && commSeq != 0) {
            dma_appendSellItem_con.set("sellItemCd", ""); // "CNTR";
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(rowPos, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(rowPos, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", ds_cntrBulkOutIntendDetail.getCellData(rowPos, "commSeq"));
        } else {
            dma_appendSellItem_con.set("sellItemCd", ""); //sellItemCd;
            dma_appendSellItem_con.set("outIntendDt", ds_cntrBulkOutIntendDetail.getCellData(rowPos, "outIntendDt"));
            dma_appendSellItem_con.set("outIntendHh", ds_cntrBulkOutIntendDetail.getCellData(rowPos, "outIntendHh"));
            dma_appendSellItem_con.set("commSeq", commSeq);
        }

        // 확정된 매출이 있는 경우 오더컨테이너 목록의 출고예정일자가 수정되지 않음
        // 이미 생성된 출고예정일자와 신규로 입력한 신규예정일자를 비교하여 집계할려는 일자보다 작을때 입력한 일자를 DataSet로 Setting
        if (dma_appendSellItem_con.get("outIntendDt") < ica_outIntendDt.getValue()) {
            dma_appendSellItem_con.set("outIntendDt", ica_outIntendDt.getValue());
        }

    }

    await $c.sbm.execute(sbm_appendWrkStpSellItem_retrieve);
};

scwin.f_CancelSellItem = async function () {
    scwin.addYn = "N";

    let confirmResult = await $c.win.confirm(MSG_CM_CRM_011);
    if (!confirmResult) return;

    let cnt = ds_unitySelling.getRowCount();
    for (let i = cnt - 1; i >= 0; i--) {
        if (ds_unitySelling.getCellData(i, "sellSeq") == "0") {
            ds_unitySelling.removeRow(i);
        }
    }

    //TODO 실제값이랑 맞지 않을 수 있으니 확인 필요
    ed_unitySellingCount.setValue(ds_unitySelling.getRowCount());	// 매출항목 수 화면에 표시

    scwin.f_SumAmt();

    let outIntendNo = ds_cntrBulkOutIntend.getCellData(0, "outIntendNo");
    if (outIntendNo.length > 0) {
        for (let j = 0; j < ds_unitySelling.getRowCount(); j++) {
            if (ds_unitySelling.getCellData(j, "outIntendNo") == outIntendNo) {
                ds_unitySelling.modifyRowStatus(j, "D");
            }
        }
        await $c.sbm.execute(sbm_cancelSellItem_save);
    }
};



