//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    else									// inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
};

//-------------------------------------------------------------------------
// 매출항목 콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveSellItem = async function (bilgLodeptCd, fmlaClsCd, fmlaPatternCd) {
    let oldParam1 = dma_sellItem.get("param1");
    let oldParam2 = dma_sellItem.get("param2");
    let oldParam3 = dma_sellItem.get("param3");

    if (oldParam1 == bilgLodeptCd && oldParam2 == fmlaClsCd && oldParam3 == fmlaPatternCd) {
        return;
    }
    let key = scwin.v_bilgLodeptCd + '|' + scwin.v_fmlaClsCd + '|' + scwin.v_fmlaPatternCd;
    if (scwin.hasSellItem(key)) {
        scwin.updateSellItemFilter(key);
        return;
    }

    const strParam = {
        sysCd: "OrderOutIntendEBC"        // 시스템코드
        , queryId: "retrieveSellItem"     // 쿼리ID
        , param1: bilgLodeptCd
        , param2: fmlaClsCd
        , param3: fmlaPatternCd
        , param4: ""
        , param5: ""
        , param6: ""
        , param7: ""
        , param8: ""
        , param9: ""
        , param10: ""
    };

    dma_sellItem.setEmptyValue();
    dma_sellItem.setJSON(strParam);

    let rtn = await $c.sbm.execute(sbm_sellItem);
    let jsonRtn = rtn.responseJSON;
    if (jsonRtn.resultDataSet[0].Code != "0") {
        return null;
    }

    let data = jsonRtn.GAUCE;

    //data에 key값 세팅
    data.forEach(function (item) {
        item.keyCode = key;
    });

    ds_sellItem.setJSON(data, true);
    scwin.updateSellItemFilter(key);
};

scwin.hasSellItem = function (key) {

    let num = ds_sellItem.getRowCount();
    for (let i = 0; i < num; i++) {
        if (ds_sellItem.getCellData(i, "keyCode") == key) {
            return true;
        }
    }
    return false;
};

scwin.updateSellItemFilter = function (key) {
    scwin.selectedKey = key;

    lds_sellItem.clearFilter();	//필터링 해제
    lds_sellItem.setColumnFilter(
        { type: 'func', colIndex: 'keyCode', key: scwin.lds_sellItemFilterFunc, condition: 'and' }
    );

    gr_unitySelling.redrawColumn("sellItemCd", true);
};

scwin.lds_sellItemFilterFunc = function (cellData, tmpParam, rowIdx) {
    if (cellData == scwin.selectedKey) {
        return true;
    }
    return false;   //return이 true인 경우 적용하고 false인 경우 skip한다.
};

