//-------------------------------------------------------------------------
// 출고정산유형 change 이벤트
//-------------------------------------------------------------------------
scwin.f_ChgoutAdjmPatternCd = async function () {
    if (rd_prebilgClsCd.getValue() == "02") {
        if (ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd") == "05") {
            if (acb_outAdjmPatternCd.getValue() == "04") {
                //오더 컨테이너 목록을 숨긴다.
                grp_cntrBulkOutIntendDetail.hide();
            } else {
                //오더 컨테이너 목록을 나타나게 한다.
                grp_cntrBulkOutIntendDetail.show();
            }
        } else {
            //오더 컨테이너 목록을 나타나게 한다.
            grp_cntrBulkOutIntendDetail.show();
        }
    } else {
        //오더 컨테이너 목록을 나타나게 한다..
        grp_cntrBulkOutIntendDetail.show();
    }

    if (acb_outAdjmPatternCd.getValue() == "09") {
        $c.gus.cfDisableBtnOnly([btn_CntrSellingItem, btn_RetrieveSellingItem]);
    } else {
        $c.gus.cfEnableBtnOnly([btn_CntrSellingItem, btn_RetrieveSellingItem]);
    }
};

//-------------------------------
// 출고지시서 버턴 클릭
//-------------------------------
scwin.f_outIndication = async function () {

    let printClsCd = "";
    let mcomAssgnClsCd = ds_cntrBulkOutIntend.getCellData(0, "mcomAssgnClsCd");
    if (mcomAssgnClsCd && (mcomAssgnClsCd.substring(0, 1) == "B" || mcomAssgnClsCd.substring(0, 2) == "ZZ")) {
        printClsCd = "99p";
    } else {
        printClsCd = "98p";
    }

    let printCopies = "1";
    let slipNo = "";
    let outAdjmStsCd = ds_cntrBulkOutIntend.getCellData(0, "outAdjmStsCd");
    if (outAdjmStsCd == "02") {
        slipNo = ds_cntrBulkOutIntend.getCellData(0, "pldgMgntNo");	//담보번호 Set...				
        printCopies = "2";		//발행부수 설정	
    } else if (outAdjmStsCd == "03") {
        slipNo = ds_cntrBulkOutIntend.getCellData(0, "slipNo");		//전표번호 Set...		
    }

    let odiName = "fs_999_99_99p";
    let reportName = "/ds/fs/fs_999_99_" + printClsCd + ".ozr";
    let odiParam = { "slipNo" : slipNo };

    let printMode = chb_printCheck.getValue() == "1" ? 'view' : 'silent';   //인쇄옵션처리
    let previewMode = chb_previewCheck.getValue() == "1";                   //미리보기처리

    if(previewMode){
        let data = {
            "odiName": odiName,
			"reportName": reportName,
			"odiParam": odiParam,
			"viewerParam": {
				"zoom": 100, // 배율 설정
			},
			"formParam": {
			}
		};
		let opts = {
			"type": 'viewer', // viewer, print, download
			"printMode": printMode,
            "printCopies" : printCopies
		};

		$c.ext.openOzReport(data, opts);

    } else {
        let data = {
            "odiName": odiName,
			"reportName": reportName,
			"odiParam": odiParam,
			"viewerParam": {
				"viewer": 100
			},
			"formParam": {
			}
		};
		let opts = {
			"type": 'print',
			"printMode": printMode,
            "printCopies" : printCopies
		};

		$c.ext.printOzReport(data, opts);
    }
};


