        rd_prebilgClsCd.focus();
        return;
    }

    if ((ed_bilgClntNo.getValue ? ed_bilgClntNo.getValue() : "") != ds_cntrBulkOutIntend.getCellData(0, "bilgClntNo")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "청구거래처", "세금계산서"));
