        return;
    }

    if ((ed_pldgClntNo.getValue ? ed_pldgClntNo.getValue() : "") != ds_cntrBulkOutIntend.getCellData(0, "pldgClntNo")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "담보거래처", "세금계산서"));
        ed_pldgClntNo.focus();
        return;
    }

    if (ed_summary.getValue() != ds_cntrBulkOutIntend.getCellData(0, "summary")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "적요", "세금계산서"));
        ed_summary.focus();
        return;
    }

    if (acb_outAdjmPatternCd.getValue() != ds_cntrBulkOutIntend.getCellData(0, "outAdjmPatternCd")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "출고정산유형", "세금계산서"));
        acb_outAdjmPatternCd.focus();
        return;
    }

    if (ica_outIntendDt.getValue() != ds_cntrBulkOutIntend.getCellData(0, "outIntendDt")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "출고예정일자", "세금계산서"));
        ica_outIntendDt.focus();
        return;
    }

    if (ed_outIntendHh.getValue() != ds_cntrBulkOutIntend.getCellData(0, "outIntendHh")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "출고예정시분", "세금계산서"));
        ed_outIntendHh.focus();
        return;
    }

    if (ed_jdgAmt.getValue() != ds_cntrBulkOutIntend.getCellData(0, "jdgAmt")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "감정가", "세금계산서"));
        ed_jdgAmt.focus();
        return;
    }

    if (ed_cstmdtAmt.getValue() != ds_cntrBulkOutIntend.getCellData(0, "cstmdtAmt")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "관세가", "세금계산서"));
        ed_cstmdtAmt.focus();
        return;
    }

    if (ds_unitySelling.getModifiedJSON().length > 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "오더매출목록", "세금계산서"));
        return;
    }

    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if ((ds_unitySelling.getCellData(i, "outIntendNo") == ds_cntrBulkOutIntend.getCellData(0, "outIntendNo")) &&
