            await $c.win.alert("거래명세서를 먼저 삭제후 작성하십시오.");
            return;
        }
    }

    let valueObject = {};
    valueObject.sellWrkRsltsNo = ds_cntrBulkOutIntend.getCellData(0, "outIntendNo");
    valueObject.sellWrkRsltsClsCd = "05";

    if (ds_cntrBulkOutIntend.getCellData(0, "slipNo") == "N" || ds_cntrBulkOutIntend.getCellData(0, "slipNo") == "") {
