        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "담보거래처", "담보"));
        ed_pldgClntNo.focus();
        return;
    }

    if (ed_summary.getValue() != ds_cntrBulkOutIntend.getCellData(0, "summary")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "적요", "담보"));
        ed_summary.focus();
        return;
    }

    if (acb_outAdjmPatternCd.getValue() != ds_cntrBulkOutIntend.getCellData(0, "outAdjmPatternCd")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "출고정산유형", "담보"));
        acb_outAdjmPatternCd.focus();
        return;
    }

    if (ica_outIntendDt.getValue() != ds_cntrBulkOutIntend.getCellData(0, "outIntendDt")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "출고예정일자", "담보"));
        ica_outIntendDt.focus();
        return;
    }

    if (ed_outIntendHh.getValue() != ds_cntrBulkOutIntend.getCellData(0, "outIntendHh")) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "출고예정시분", "담보"));
        ed_outIntendHh.focus();
        return;
    }

    if (ds_unitySelling.getModifiedJSON().length > 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_042, "오더매출목록", "담보"));
        return;
    }

    let valueObject = {};

    valueObject.outIntendNo = ds_cntrBulkOutIntend.getCellData(0, "outIntendNo");
    valueObject.sellWrkRsltsClsCd = "05";

    if (ds_cntrBulkOutIntend.getCellData(0, "pldgMgntNo") == "N" || ds_cntrBulkOutIntend.getCellData(0, "pldgMgntNo") == "") {
        valueObject.pldgMgntNo = "";
    } else {
        valueObject.pldgMgntNo = ds_cntrBulkOutIntend.getCellData(0, "pldgMgntNo");
    }

    valueObject.bilgLodeptCd = ds_cntrBulkOutIntend.getCellData(0, "bilgLodeptCd");
    valueObject.bilgClntNo = ds_cntrBulkOutIntend.getCellData(0, "pldgClntNo");
    valueObject.taxnClsCd = ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd");
    valueObject.fmlaClsCd = "01";
    valueObject.fmlaPatternCd = ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd");

    let result = await $c.win.openPopup("/ui/ds/fs/bilg/fs_202_06_07p.xml",
        { width: 620, height: 440, modal: true },
        valueObject
    );

    ed_outIntendNoSearch.setValue(ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));

    scwin.f_Retrieve("Button");
};

