/* ========================================
* 함수명: f_AmtDivision
* 설 명: 매출 금액 분할 기능
* 기 능:
*   - 하나의 매출항목을 여러 항목으로 분할하여 각기 다른 금액 설정 가능
*   - 원본 행과 분할 행을 연결하여 관리
* 제약사항:
*   - 데이터가 저장된 상태에서만 가능
*   - 원본 데이터만 분할 가능 (이미 분할된 데이터는 불가)
*   - 확정된 데이터는 분할 불가
*   - 미저장 분할 금액이 있으면 추가 불가
* ======================================== */
scwin.f_AmtDivision = async function () {
    // 매출항목이 없는 경우 에러
    if (ds_unitySelling.getRowCount() < 1) {
        await $c.win.alert(scwin.MSG_SD_WRN_009);	// "원본 데이타가 존재하지 않습니다."	
        return;
    }

    // 이미 분할된 데이터인 경우 (분할 불가)
    let curRowIndex = ds_unitySelling.getRowPosition();
    if (ds_unitySelling.getCellData(curRowIndex, "bilgTrgtOdrNo") != "") {
        await $c.win.alert(scwin.MSG_SD_WRN_015);	// "원본 데이타만 금액분할이 가능합니다."
        return;
    }

    // 미저장 상태의 분할 데이터 존재 여부 확인
    let isChild = false;
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (ds_unitySelling.getCellData(curRowIndex, "odrNo") == ds_unitySelling.getCellData(i, "bilgTrgtOdrNo") &&
            ds_unitySelling.getCellData(curRowIndex, "sellSeq") == ds_unitySelling.getCellData(i, "bilgTrgtSellSeq") &&
            ds_unitySelling.getCellData(i, "volAmtDivsClsCd") == "C") {
            isChild = true;
            break;
        }
    }

    if (isChild) {
        await $c.win.alert(scwin.MSG_SD_WRN_016);
        return;
    }

    if (ds_unitySelling.getRowStatus(curRowIndex) != "R") {
        await $c.win.alert(scwin.MSG_SD_WRN_011);
        return;
    }

    if (ds_unitySelling.getCellData(curRowIndex, "dcsnClsCd") != "1") {
        await $c.win.alert(scwin.MSG_SD_WRN_014);
        return;
    }

    let newRowIndex = curRowIndex + 1;
    ds_unitySelling.insertRow(newRowIndex);
    let colCount = ds_unitySelling.getColumnCount();
    for (let j = 0; j < colCount; j++) {
        let colId = ds_unitySelling.getColumnID(j);
        if (colId == "sellAmt") {
            ds_unitySelling.setCellData(newRowIndex, "sellAmt", 0);
        } else if (colId == "vatAmt") {
            ds_unitySelling.setCellData(newRowIndex, "vatAmt", 0);
        } else if (colId == "sumSellAmt") {
            ds_unitySelling.setCellData(newRowIndex, "sumSellAmt", 0);
        } else if (colId == "sellUpr") {
            ds_unitySelling.setCellData(newRowIndex, "sellUpr", 0);
        } else {
            ds_unitySelling.setCellData(newRowIndex, colId, ds_unitySelling.getCellData(curRowIndex, colId));
        }
    }

    ds_unitySelling.setCellData(newRowIndex, "bilgTrgtSellSeq", ds_unitySelling.getCellData(curRowIndex, "sellSeq"));
    ds_unitySelling.setCellData(newRowIndex, "bilgTrgtOdrNo", ds_unitySelling.getCellData(curRowIndex, "odrNo"));
    ds_unitySelling.setCellData(newRowIndex, "volAmtDivsClsCd", "C");
    ds_unitySelling.setCellData(newRowIndex, "choice", "F");
    ds_unitySelling.setCellData(newRowIndex, "outIntendNo", "");
    ds_unitySelling.setCellData(newRowIndex, "outIntendSeq", "");
    ds_unitySelling.setCellData(newRowIndex, "sellSeq", 0);

    scwin.f_findParentRow(newRowIndex);

    ds_unitySelling.setCellData(curRowIndex, "volAmtDivsClsCd", "A");

    gr_unitySelling.setFocusedCell(newRowIndex, "sellAmt");
    gr_unitySelling.setColumnReadOnly("choice", false);
    gr_unitySelling.setReadOnly("grid", false);
};

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------		
scwin.f_CancelRow = async function () {

    let rowIndex = ds_unitySelling.getRowPosition();
    if(rowIndex < 0) {
        return;
    }

    let rowStatus = ds_unitySelling.getRowStatus(rowIndex);
    if(rowStatus == "C") {
        ds_unitySelling.removeRow(rowIndex);
    } else {
        ds_unitySelling.undoRow(rowIndex);
    }

    scwin.f_SumAmt();
};

//-------------------------------------------------------------------------
// 금액분할 원본ROW 찾기
//-------------------------------------------------------------------------	
scwin.f_findParentRow = async function (row) {
    scwin.fitRow = 0;
    let bilgTrgtOdrNo = ds_unitySelling.getCellData(row, "bilgTrgtOdrNo");
    let bilgTrgtSellSeq = ds_unitySelling.getCellData(row, "bilgTrgtSellSeq");
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (ds_unitySelling.getCellData(i, "odrNo") == bilgTrgtOdrNo &&
            ds_unitySelling.getCellData(i, "sellSeq") == bilgTrgtSellSeq &&
            ds_unitySelling.getCellData(i, "bilgTrgtOdrNo") == "") {
            scwin.fitRow = i;
        }
    }
};

//-------------------------------------------------------------------------
// 매출물량 세팅
//-------------------------------------------------------------------------	
scwin.f_SetSellVol = async function (row) {
    ds_unitySelling.setCellData(row, "unitClsCd", ds_sellUnitCd.getCellData(row, "name"));
    for (let i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
        let sellUnitCd = ds_unitySelling.getCellData(row, "sellUnitCd");
        if (sellUnitCd == "CBM") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "cntrNo") == ds_unitySelling.getCellData(row, "sellCommNo")) {
                ds_unitySelling.setCellData(row, "sellVol", ds_cntrBulkOutIntendDetail.getCellData(i, "cbm"));
                ds_unitySelling.setCellData(row, "bilgUnitCd", sellUnitCd);
            }
        } else if (sellUnitCd == "MST") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "cntrNo") == ds_unitySelling.getCellData(row, "sellCommNo")) {
                ds_unitySelling.setCellData(row, "sellVol", scwin.f_Round((Number(ds_cntrBulkOutIntendDetail.getCellData(i, "cbm")) / 1.133), 3, "F"));
                ds_unitySelling.setCellData(row, "bilgUnitCd", sellUnitCd);
            }
        } else if (sellUnitCd == "R/T") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "cntrNo") == ds_unitySelling.getCellData(row, "sellCommNo")) {
                let v_Wt = scwin.cfConvert2Weight(ds_cntrBulkOutIntendDetail.getCellData(i, "wt"), "KG", "TON");
                let v_Cbm = Number(ds_cntrBulkOutIntendDetail.getCellData(i, "cbm"));
                if (v_Wt > v_Cbm) {
                    ds_unitySelling.setCellData(row, "sellVol", v_Wt);
                    ds_unitySelling.setCellData(row, "bilgUnitCd", "K/T");
                } else {
                    ds_unitySelling.setCellData(row, "sellVol", v_Cbm);
                    ds_unitySelling.setCellData(row, "bilgUnitCd", "CBM");
                }
            }
        } else if (sellUnitCd == "RNT") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "cntrNo") == ds_unitySelling.getCellData(row, "sellCommNo")) {
                let v_Wt = scwin.cfConvert2Weight(ds_cntrBulkOutIntendDetail.getCellData(i, "wt"), "KG", "TON");
                let v_Cbm = scwin.f_Round((Number(ds_cntrBulkOutIntendDetail.getCellData(i, "cbm")) / 1.133), 3, "F");
                if (v_Wt > v_Cbm) {
                    ds_unitySelling.setCellData(row, "sellVol", v_Wt);
                    ds_unitySelling.setCellData(row, "bilgUnitCd", "K/T");
                } else {
                    ds_unitySelling.setCellData(row, "sellVol", v_Cbm);
                    ds_unitySelling.setCellData(row, "bilgUnitCd", "MST");
                }
            }
        } else if (sellUnitCd == "TON") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "cntrNo") == ds_unitySelling.getCellData(row, "sellCommNo")) {
                let v_Wt = scwin.cfConvert2Weight(ds_cntrBulkOutIntendDetail.getCellData(i, "wt"), "KG", "TON");
                ds_unitySelling.setCellData(row, "sellVol", v_Wt);
                ds_unitySelling.setCellData(row, "bilgUnitCd", sellUnitCd);
            }
        } else if (sellUnitCd == "VAN") {
            ds_unitySelling.setCellData(row, "sellVol", 1);
            ds_unitySelling.setCellData(row, "bilgUnitCd", sellUnitCd);
        }
    }

    ds_unitySelling.setCellData(row, "sellAmt", Number(ds_unitySelling.getCellData(row, "sellUpr")) * Number(ds_unitySelling.getCellData(row, "sellVol")));
    if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01") {
        ds_unitySelling.setCellData(row, "vatAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) * 0.1);
    } else {
        ds_unitySelling.setCellData(row, "vatAmt", 0);
    }
    ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));
};

