scwin.f_BalUnpaid = async function () {
    for (let i = 0; i < ds_unitySelling.getRowCount(); i++) {
        if (ds_unitySelling.getCellData(i, "choice") != "T") {
            continue;
        }

        let b_sellAmt = Number(ds_unitySelling.getCellData(i, "sellAmt")).toString();
        let b_vatAmt = (scwin.f_Round(Number(ds_unitySelling.getCellData(i, "vatAmt")), 0, "F")).toString();

        b_sellAmt = b_sellAmt.substr(0, b_sellAmt.length - 1);
        b_vatAmt = b_vatAmt.substr(0, b_vatAmt.length - 1);

        b_vatAmt = b_sellAmt;
        b_sellAmt = b_sellAmt + "0";

        ds_unitySelling.setCellData(i, "sellAmt", b_sellAmt);
        ds_unitySelling.setCellData(i, "vatAmt", b_vatAmt);
        ds_unitySelling.setCellData(i, "sumSellAmt", Number(ds_unitySelling.getCellData(i, "sellAmt")) + Number(ds_unitySelling.getCellData(i, "vatAmt")));
    }
    scwin.f_SumAmt();
};

