//-------------------------------------------------------------------------
//전자수납 사용하는 점소 구분
//-------------------------------------------------------------------------
scwin.f_elecReceiptYn = async function () {

    // 경기지사 전자수납 사용.
    // 20150310 - 부산지사도 적용

    // 청구부서의 최상위 부서 구하기
    let upperLobranCd = await scwin.getUpperLobran(ed_bilgLodeptCd.getValue() ?? "");

    // alert("gv_userId >>> " + gv_userId);
    // SITC_LOGI에서 등록한 선수납도 전자수납 대상 제외 -> LoginId가 sitc3353인 Id도 제외 시키면 됨
    // 청구부서의 최상위 부서가 경기지사 또는 부산지사 이고, 선청구구분이 영수인 경우 if문 탐

    // 4월 20일 부산지사 전자수납 반영 예정 (20일 이후에 IF문 아래의 주석 내용으로 수정 요망)
    // 2015.05.21 수정 (테스트상태 에서는 주석 풀기) -> 개발 후 다시 주석막던지 하는건 추후 협의
    if ((upperLobranCd == "4BB" || upperLobranCd != "6AA") && rd_prebilgClsCd.getValue() == "02" && scwin.userId != 'sitc3353') {
        if (scwin.elecReceiptExcept != "") {
            // 청구거래처와 전자수납제외거래처가 동일하면 전자수납 제외
            if (ed_bilgClntNo.text == scwin.elecReceiptExcept) {
                ds_cntrBulkOutIntend.setCellData(0, "elecReceipYn", 0);
                return;
            }
            // 청구거래처와 전자수납제외거래처가 동일하지 않으면 전자수납 제외 안함
            else {
                ds_cntrBulkOutIntend.setCellData(0, "elecReceipYn", 1);
            }
        }

        //  CY후불거래처의 전자수납 제외 LIST가 없으면 전자수납 제외 안함
        else {
            ds_cntrBulkOutIntend.setCellData(0, "elecReceipYn", 1);
        }
    }

    // 청구부서의 최상위 부서가 경기지사 또는 부산지사 가 아니고, 선청구인 경우 전자수납 제외 함
    else {
        ds_cntrBulkOutIntend.setCellData(0, "elecReceipYn", 0);
    }
};

scwin.f_elecReceiptCntl = async function (flag) {

    //전자수납대상이고, 응답여부가 승인상태 인 경우
    if (ds_cntrBulkOutIntend.getCellData(0, "elecReceipYn") == 1
        && scwin.responseTypeInfo == "L") {
        // 2015.08.20 
        // 승인 상태인 경우, 청구처거래처 수정 만, 수정 가능토록 함.
        let tempBilgClntNo = ds_cntrBulkOutIntend.getCellData(0, "bilgClntNo");

        ds_cntrBulkOutIntend.undoAll();
        ds_cntrBulkOutIntendDetail.undoAll();
        ds_unitySelling.undoAll();

        if (tempBilgClntNo != ds_cntrBulkOutIntend.getOriginalCellData(0, "bilgClntNo")) {

            await scwin.f_elecReceiptYn();

            ds_cntrBulkOutIntend.setCellData(0, "bilgClntNo", tempBilgClntNo);

            for (var k = 0; k < ds_unitySelling.CountRow; k++) {
                if (ds_unitySelling.getCellData(k, "choice") == "T") {
                    ds_unitySelling.setCellData(k, "bilgClntNo", tempBilgClntNo);		// 청구거래처코드
                }

            }
        }

        return true;
    }

    //전자수납대상이고, 응답여부가 전송대기상태 인 경우
    else if (ds_cntrBulkOutIntend.getCellData(0, "elecReceipYn") == 1 && scwin.responseTypeInfo == "W") {

        const strParam = {
            sysCd: "CommonEBC"                       // 시스템코드
            , queryId: "retrieveElecReceiptResponseType2"     // 쿼리ID
            , param1: ds_cntrBulkOutIntend.getCellData(0, "outIntendNo")
            , param2: ""
            , param3: ""
            , param4: ""
            , param5: ""
            , param6: ""
            , param7: ""
            , param8: ""
            , param9: ""
            , param10: ""
        };

        dma_commonCode.setEmptyValue();
        dma_commonCode.setJSON(strParam);
        let ret = await $c.sbm.execute(sbm_commonCode);
        let responseJSON = ret.responseJSON;
        if (responseJSON.resultDataSet[0].Code != 0) {
            return false;
        }

        let gauce = responseJSON.GAUCE;
        let result = gauce[0].col2;

        if (flag == "U") {
            if (result == "WAIT") {
                return true;
            }
            else {
                $c.win.alert("전송대기 상태는 수정, 삭제 불가 합니다.");
                return false;
            }
        }
        else if (flag == "D") {
            if (result == "WAIT") {
                return true;
            }
            else {
                $c.win.alert("전송대기 상태는 수정, 삭제 불가 합니다.");
                return false;
            }
        }
    }
    else {
        return true;
    }

};

