        return;
    }

    if (scwin.delflag == "DEL") {
        ed_outIntendNoSearch.setValue("");
        await $c.win.alert(MSG_CM_INF_004);
        scwin.delflag = "";
        scwin.f_Retrieve("Enter");
    } else {
        if (ed_outIntendNo.getValue() == "") {
            ed_outIntendNoSearch.setValue(ds_odrOutIntend.getCellData(0, "outIntendNo"));
        } else {
            ed_outIntendNoSearch.setValue(ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));
        }
