// 조회되었을때 화면에 데이터 바인딩.
scwin.ds_cntrBulkOutIntend_ondataload = async function (e) {


    let rowcnt = ds_cntrBulkOutIntend.getRowCount();
    if (rowcnt > 0) {
        ed_outIntendNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));
        ed_bilgLodeptCd.setValue(ds_cntrBulkOutIntend.getCellData(0, "bilgLodeptCd"));
        ed_sellLodeptCd.setValue(ds_cntrBulkOutIntend.getCellData(0, "sellLodeptCd"));
        ed_bilgLodeptNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "bilgLodeptNm"));
        ed_sellLodeptNm.setValue("");
        //ed_sellLodeptCd.focus();
        //ed_sellLodeptNm.focus();
        scwin.f_chkOpenCommonPopUp(ed_sellLodeptCd, ed_sellLodeptNm, 4);
        ed_dptWrkPlNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "dptWrkPlNm"));
        ed_odrNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "odrNo"));

        scwin._odrDcsnYn = ds_cntrBulkOutIntend.getCellData(0, "odrDcsnYn");	/*오더확정 구분*/

        if (scwin._odrDcsnYn == "1") {	// 확정이 되지 않은 건에 대해서는 담보만 가능 함 - 20060809 김태원 수정
            $c.gus.cfEnableBtnOnly([btn_TaxEstimat]);
        } else {
            $c.gus.cfDisableBtnOnly([btn_TaxEstimat]);
        }
        ed_ctrtNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "ctrtNo"));

        if (ed_outIntendNo.getValue() == '') {
            rd_prebilgClsCd.setValue("02");
            acb_outAdjmPatternCd.setValue("06");

            //2016.12.28 이신미 추가 EAS라인, 수입자가반출일 경우 선청구, 무매출 세팅
            let fmlaPatternCd = ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd");
            let lineCd = ds_cntrBulkOutIntend.getCellData(0, "lineCd");
            if (fmlaPatternCd == "06" && (lineCd == "EAS"
                || lineCd == "EVER"
                || lineCd == "EMS"
                || lineCd == "HTML"
                || lineCd == "ITS"
                || lineCd == "RCL"
                || lineCd == "COH"
                || lineCd == "SITC"
                || lineCd == "TCLC"
                || lineCd == "JJS"
                || lineCd == "NOLS"
                || lineCd == "DWH"
                || lineCd == "MAS"
                || lineCd == "EGH"
                || lineCd == "EMA"
            )) {

                rd_prebilgClsCd.setValue('01');
                acb_outAdjmPatternCd.setValue("09");
            }
        } else {
            acb_outAdjmPatternCd.setValue(ds_cntrBulkOutIntend.getCellData(0, "outAdjmPatternCd"));
            rd_prebilgClsCd.setValue(ds_cntrBulkOutIntend.getCellData(0, "prebilgClsCd"));
        }

        ed_pldgClntNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "pldgClntNo"));
        ed_pldgClntNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "pldgClntNm"));
        ed_bilgClntNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "bilgClntNo"));
        ed_bilgClntNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "bilgClntNm"));

        // 2015.05.21 입금거래처 추가
        if (ed_outIntendNo.getValue() == '') {
            if (ds_cntrBulkOutIntend.getCellData(0, "depositClntNo") == '') {
                ds_cntrBulkOutIntend.setCellData(0, "depositClntNo", ds_cntrBulkOutIntend.getCellData(0, "bilgClntNo"));
                ds_cntrBulkOutIntend.setCellData(0, "depositClntNm", ds_cntrBulkOutIntend.getCellData(0, "bilgClntNm"));
            }
        }

        ed_depositClntNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "depositClntNo"));
        ed_depositClntNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "depositClntNm"));

        let taxnClsCd = ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd");
        let taxnClsCdStr = "";
        if (taxnClsCd == "01") {
            taxnClsCdStr = "과세";
        } else if (taxnClsCd == "02") {
            taxnClsCdStr = "영세";
        } else if (taxnClsCd == "03") {
            taxnClsCdStr = "영세기타";
        } else if (taxnClsCd == "04") {
            taxnClsCdStr = "과세기타";
        }

        ed_taxnClsCd.setValue(taxnClsCdStr);
        ed_slipPldgNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "sellVatNo") + '/' + ds_cntrBulkOutIntend.getCellData(0, "pldgMgntNo"));
        ed_blNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "blNo"));
        scwin._bondMcom = ds_cntrBulkOutIntend.getCellData(0, "bondTransExpireDt") + '/' + ds_cntrBulkOutIntend.getCellData(0, "mcomAssgnClsCd");

        let arrvlportDt = ds_cntrBulkOutIntend.getCellData(0, "arrvlportDt");
        ed_arrvlportDt.setValue(arrvlportDt.substring(0, 4) + '/' + arrvlportDt.substring(4, 6) + '/' + arrvlportDt.substring(6, 8));
        ed_jdgAmt.setValue(ds_cntrBulkOutIntend.getCellData(0, "jdgAmt"));
        ed_cstmdtAmt.setValue(ds_cntrBulkOutIntend.getCellData(0, "cstmdtAmt"));
        ed_selfClsNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "selfClsNm"));
        ed_wrkPl.setValue(ds_cntrBulkOutIntend.getCellData(0, "dptWrkPlNm") + '-' + ds_cntrBulkOutIntend.getCellData(0, "arvWrkPlNm"));
        ed_crryoutAdmitNo.setValue(ds_cntrBulkOutIntend.getCellData(0, "crryoutAdmitNo"));
        ed_admitDropDt.setValue(ds_cntrBulkOutIntend.getCellData(0, "admitDropDt"));
        ed_line.setValue(ds_cntrBulkOutIntend.getCellData(0, "lineCd") + '/' + ds_cntrBulkOutIntend.getCellData(0, "vsslCd") + '/' + ds_cntrBulkOutIntend.getCellData(0, "portcnt"));

        let outAdjmStsCd = ds_cntrBulkOutIntend.getCellData(0, "outAdjmStsCd");
        let outAdjmStsCdStr = "";
        if (outAdjmStsCd == "01") {
            outAdjmStsCdStr = "생성";
            $c.gus.cfDisableBtnOnly([btn_OutIndication]);
        } else if (outAdjmStsCd == "02") {
            outAdjmStsCdStr = "담보";
            $c.gus.cfEnableBtnOnly([btn_OutIndication]);
        } else if (outAdjmStsCd == "03") {
            outAdjmStsCdStr = "계산서";
            $c.gus.cfEnableBtnOnly([btn_OutIndication]);
        } else {
            ds_cntrBulkOutIntend.setCellData(0, "outAdjmStsCd", "01");
            outAdjmStsCdStr = "생성";
            $c.gus.cfDisableBtnOnly([btn_OutIndication]);
        }
        ed_outAdjmStsCd.setValue(outAdjmStsCdStr);

        ed_summary.setValue(ds_cntrBulkOutIntend.getCellData(0, "summary"));

        let outIntendDt = ds_cntrBulkOutIntend.getCellData(0, "outIntendDt");
        if (outIntendDt == "") {
            ica_outIntendDt.setValue(scwin.strCurDate);
        } else {
            ica_outIntendDt.setValue(outIntendDt);
        }

        let outIntendHh = ds_cntrBulkOutIntend.getCellData(0, "outIntendHh");
        if (outIntendHh == "") {
            ed_outIntendHh.setValue(scwin.currentTime);
        } else {
            ed_outIntendHh.setValue(outIntendHh);
        }

        ed_spplyAmt.setValue(ds_cntrBulkOutIntend.getCellData(0, "spplyAmt"));
        ed_vatAmt.setValue(ds_cntrBulkOutIntend.getCellData(0, "vatAmt"));
        ed_totAmt.setValue(ds_cntrBulkOutIntend.getCellData(0, "spplyAmt") + ds_cntrBulkOutIntend.getCellData(0, "vatAmt"));
        ed_pldgAmt.setValue(ds_cntrBulkOutIntend.getCellData(0, "pldgAmt"));
        ed_whouseClsNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "whouseClsNm") + '/' + ds_cntrBulkOutIntend.getCellData(0, "arvDtl"));
        ed_packCnt.setValue(ds_cntrBulkOutIntend.getCellData(0, "packCnt"));
        ed_totWt.setValue(scwin.cfConvert2Weight(ds_cntrBulkOutIntend.getCellData(0, "totWt"), "KG", "TON"));
        ed_totCbm.setValue(ds_cntrBulkOutIntend.getCellData(0, "totCbm"));
        ed_rmk.setValue(ds_cntrBulkOutIntend.getCellData(0, "rmk"));

        // 청구부서의 최상위 부서 구하기
        let upperLobranCd = await scwin.getUpperLobran(ed_bilgLodeptCd.getValue() ?? "");

        if (upperLobranCd == "4BB") {
            if (ds_cntrBulkOutIntend.getCellData(0, "issudcRmk") == '') {
                ed_issudcRmk.setValue("16:30분까지 수납분에 한에 상차 가능합니다.");
            }
            else {
                ed_issudcRmk.setValue(ds_cntrBulkOutIntend.getCellData(0, "issudcRmk"));
            }

            if (ds_cntrBulkOutIntend.getCellData(0, "issudcExpireDt") == '') {
                ica_issudcExpireDt.setValue(scwin.strCurDate);
            }
            else {
                ica_issudcExpireDt.setValue(ds_cntrBulkOutIntend.getCellData(0, "issudcExpireDt") ?? "");
            }
        } else if (upperLobranCd == "6AA") {
            if (ds_cntrBulkOutIntend.getCellData(0, "issudcRmk") == '') {
                ed_issudcRmk.setValue("※통장-외환은행: 630-005118-137(동부EXP), ※이체증(FAX): 051-461-0953");
            }
            else {
                ed_issudcRmk.setValue(ds_cntrBulkOutIntend.getCellData(0, "issudcRmk"));
            }

            if (ds_cntrBulkOutIntend.getCellData(0, "issudcExpireDt") == '') {
                ica_issudcExpireDt.setValue(scwin.strCurDate2);
            }
            else {
                ica_issudcExpireDt.setValue(ds_cntrBulkOutIntend.getCellData(0, "issudcExpireDt") ?? "");
            }
        } else {
            ed_issudcRmk.setValue(ds_cntrBulkOutIntend.getCellData(0, "issudcRmk"));
            ica_issudcExpireDt.setValue(ds_cntrBulkOutIntend.getCellData(0, "issudcExpireDt") ?? "");
        }

        acb_responsetype.setValue(ds_cntrBulkOutIntend.getCellData(0, "responsetype"));
        acb_sndcoftype.setValue(ds_cntrBulkOutIntend.getCellData(0, "sndcoftype"));

        if (ds_cntrBulkOutIntend.getCellData(0, "prebilgClsCd") == "01") {
            acb_fmlaPatternCd.setValue(ds_cntrBulkOutIntend.getCellData(0, "fmlaClsCd") + ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd"));
        } else {
            ed_fmlaPatternNm.setValue(ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternNm"));
        }

        if (ds_cntrBulkOutIntend.getCellData(0, "outAdjmStsCd") == "03") {
            $c.gus.cfDisableBtn(["btn_PldgMgnt"]);
        } else {
            $c.gus.cfEnableBtnOnly(["btn_PldgMgnt"]);
        }

        scwin.f_ChgprebilgClsCd();
        scwin.f_ChgoutAdjmPatternCd();

        ed_odrNo.setReadOnly(true);
        btn_ordNo.setDisabled(true);

        scwin.v_bilgLodeptCd = ed_bilgLodeptCd.getValue();

        scwin.v_fmlaClsCd = ds_cntrBulkOutIntend.getCellData(0, "fmlaClsCd");
        scwin.v_fmlaPatternCd = ds_cntrBulkOutIntend.getCellData(0, "fmlaPatternCd");

        if (ed_outIntendNo.getValue() == '') {
            let odrKndCd = ds_cntrBulkOutIntend.getCellData(0, "odrKndCd");

            if (odrKndCd == "C1" || odrKndCd == "C3" ||
                (odrKndCd == "C2" && ds_cntrBulkOutIntend.getCellData(0, "sellClntClsCd") == "01")) {
                rd_prebilgClsCd.setValue('01');
                acb_fmlaPatternCd.setValue("0304");
                scwin.v_fmlaClsCd = "03";
                scwin.v_fmlaPatternCd = "04";
            }
        }

        await scwin.f_RetrieveSellItem(scwin.v_bilgLodeptCd, scwin.v_fmlaClsCd, scwin.v_fmlaPatternCd);

        if (rd_prebilgClsCd.getValue() == "01") {	// 01: 선청구
            ed_fmlaPatternNm.hide();				// 일반 청구유형 숨김
            acb_fmlaPatternCd.show();				// 선청구 유형 표시
            if (ed_outIntendNo.getValue() != '') {
                acb_fmlaPatternCd.setDisabled(true);
            } else {
                acb_fmlaPatternCd.setDisabled(false);
            }
        } else {									// 02: 선수납(후청구)
            ed_fmlaPatternNm.show();				// 일반 청구유형 표시
            acb_fmlaPatternCd.hide();				// 선청구 유형 숨김
        }

        if (ds_cntrBulkOutIntend.getCellData(0, "outAdjmStsCd") == "03") {
            $c.gus.cfDisableBtnOnly([btn_AmtDivision, btn_RetrieveSellingItem, btn_CancelSellingItem, btn_AddRow, btn_DeleteRow, btn_CancelRow, btn_Save, btn_Delete, btn_BalUnpaid]);
            gr_cntrBulkOutIntendDetail.setReadOnly("grid", true);
            ica_outIntendDt.setDisabled(true);
            ed_outIntendHh.setDisabled(true);
        } else {
            $c.gus.cfEnableBtnOnly([btn_AmtDivision, btn_RetrieveSellingItem, btn_CancelSellingItem, btn_AddRow, btn_DeleteRow, btn_CancelRow, btn_Save, btn_Delete, btn_BalUnpaid]);
            gr_cntrBulkOutIntendDetail.setReadOnly("grid", false);
            ica_outIntendDt.setDisabled(false);
            ed_outIntendHh.setDisabled(false);
        }

        if (ed_outIntendNo.getValue() == "") {
            acb_outAdjmPatternCd.setDisabled(false);
            $c.gus.cfDisableBtnOnly([btn_Delete]);
        } else {
            $c.gus.cfEnableBtnOnly([btn_Delete]);
        }

    } else {
        $c.win.alert(MSG_CM_WRN_002);
        $c.gus.cfDisableBtn([btn_Delete]);
    }

    ///// sbm_cntrOutIntend_retrieve_submitdone 에서 처리하던 것을 이동시킴 ⬇️
    if ($c.gus.cfIsNull(ed_outIntendNo.getValue())) {
        rd_prebilgClsCd.setDisabled(false);
    }
    else {
        rd_prebilgClsCd.setDisabled(true);
    }

    let upperLobranCd = await scwin.getUpperLobran(ed_bilgLodeptCd.getValue() ?? "");

    if (upperLobranCd == "6AA" && $c.gus.cfIsNull(ed_outIntendNo.getValue())) {
        ica_issudcExpireDt.setValue(scwin.strCurDate2);
        ed_issudcRmk.setValue("※통장-외환은행: 630-005118-137(동부EXP), ※이체증(FAX): 051-461-0953");
    }

    if (upperLobranCd == "4BB" && $c.gus.cfIsNull(ed_outIntendNo.getValue())) {
        ica_issudcExpireDt.setValue(scwin.strCurDate);
        ed_issudcRmk.setValue("16:30분까지 수납분에 한에 상차 가능합니다.");
    }
    ///// sbm_cntrOutIntend_retrieve_submitdone 에서 처리하던 것을 이동시킴 ⬆️

    gr_cntrBulkOutIntendDetail.setFocusedCell(0, 1);
};

// ds_cntrBulkOutIntendDetail OnLoadCompleted
scwin.ds_cntrBulkOutIntendDetail_ondataload = function (e) {
    let rowcnt = ds_cntrBulkOutIntendDetail.getRowCount();
    if (rowcnt > 0) {
        scwin.f_DivAllAmt();
        for (let i = 0; i < rowcnt; i++) {
            ds_cntrBulkOutIntendDetail.setCellData(i, "qty", 1);
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
                if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") == "") {
                    ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendDt", ica_outIntendDt.getValue());
                }
                if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendHh") == "") {
                    ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendHh", ed_outIntendHh.getValue());
                }
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") != "" && ds_cntrBulkOutIntendDetail.getCellData(i, "outCrryinoutDt") != "") {
                ds_cntrBulkOutIntendDetail.setCellData(i, "overCnt", $c.date.diffDate(ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt"), ds_cntrBulkOutIntendDetail.getCellData(i, "outCrryinoutDt")));
            }
            scwin.f_PostSumAmt(i);
        }
    }

    ed_cntrBulkOutIntendDetailCount.setValue(rowcnt);
};

// ds_unitySelling OnLoadCompleted
scwin.ds_unitySelling_ondataload = function (e) {

    let rowcnt = ds_unitySelling.getRowCount();

    ed_unitySellingCount.setValue(rowcnt);

    if (rowcnt > 0) {
        scwin.f_SumAmt();
        //출고예정일자 세팅

        let maxRsltsStdDt = "";
        //ds_unitySelling에서 getAllJSON 함수를 이용해 받아온 json 데이터 중에 rsltsStdDt 라는 날짜 데이터의 최대값을 검색한다.
        ds_unitySelling.getAllJSON().forEach(function (item) {
            let temp = item.rsltsStdDt;
            if (temp == "")
                return;

            if (maxRsltsStdDt == "") {
                maxRsltsStdDt = temp;

            }
            else if (temp > maxRsltsStdDt) {
                maxRsltsStdDt = temp;
            }
        });


        if (maxRsltsStdDt == '') {
            ica_rsltsStdDt.setValue(scwin.strCurDate);
        } else {
            ica_rsltsStdDt.setValue(maxRsltsStdDt);
        }

    } else {
        ica_rsltsStdDt.setValue(scwin.strCurDate);
    }

    $c.gus.cfGoPrevPosition(gr_unitySelling, scwin.prevRow);


    gr_unitySelling.setFocusedCell(0, 1);
};

// ds_appendSellItem OnLoadCompleted
scwin.ds_appendSellItem_ondataload = function (e) {
    let rowcnt = ds_appendSellItem.getRowCount();
    if (rowcnt <= 0) {
        return;
    }

    let app_mod = "";
    for (let app_idx = 0; app_idx < ds_appendSellItem.getRowCount(); app_idx++) {
        app_mod = "";
        for (let org_idx = 0; org_idx < ds_unitySelling.getRowCount(); org_idx++) {
            if (scwin.closeFlag == "TRUE") {
                let colCount = ds_unitySelling.getColumnCount();
                let rp = ds_unitySelling.getRowPosition();
                for (let j = 0; j < colCount; j++) {
                    let colId = ds_unitySelling.getColumnID(j);
                    let newData = ds_appendSellItem.getCellData(app_idx, colId);
                    if (newData != undefined) {
                        ds_unitySelling.setCellData(rp, colId, newData);
                    }
                }
                app_mod = "수정";
                break;
            }
            if (ds_appendSellItem.getCellData(app_idx, "strRateYn") == "0") {
                if (ds_unitySelling.getCellData(org_idx, "sellItemCd") == ds_appendSellItem.getCellData(app_idx, "sellItemCd") &&
                    ds_unitySelling.getCellData(org_idx, "commSeq") == ds_appendSellItem.getCellData(app_idx, "commSeq") &&
                    ds_unitySelling.getCellData(org_idx, "dcScCd") == ds_appendSellItem.getCellData(app_idx, "dcScCd")) {
                    app_mod = "수정";
                    break;
                }
            } else if (ds_appendSellItem.getCellData(app_idx, "strRateYn") == "1") {
                if (ds_unitySelling.getCellData(org_idx, "sellItemCd") == ds_appendSellItem.getCellData(app_idx, "sellItemCd") &&
                    ds_unitySelling.getCellData(org_idx, "commSeq") == ds_appendSellItem.getCellData(app_idx, "commSeq") &&
                    ds_unitySelling.getCellData(org_idx, "dcScCd") == ds_appendSellItem.getCellData(app_idx, "dcScCd") &&
                    ds_unitySelling.getCellData(org_idx, "wrkEndDt") == ds_appendSellItem.getCellData(app_idx, "wrkEndDt")) {
                    app_mod = "수정";
                    break;
                }
            }
        }
        if (app_mod != "수정") {

            if(ds_unitySelling.getRowCount() < 1) {
                $c.gus.cfCopyDataSetHeader(ds_appendSellItem,ds_unitySelling);
            } 

            let newRowIndex = ds_unitySelling.insertRow();
            let rowJSON = ds_appendSellItem.getRowJSON(app_idx);
            ds_unitySelling.setRowJSON(newRowIndex, rowJSON, true);
            //let colCount = ds_unitySelling.getColumnCount();
            //for (let j = 0; j < colCount; j++) {
            //    let colId = ds_unitySelling.getColumnID(j);
            //    ds_unitySelling.setCellData(newRowIndex, colId, ds_appendSellItem.getCellData(app_idx, colId));
            //}
        }
    }
    ed_unitySellingCount.setValue(ds_unitySelling.getRowCount());
    gr_unitySelling.setReadOnly("grid", false);
};

scwin.ds_cntrBulkOutIntendDetail_onrowpositionchange = function (info) {
    let oldRow = info.oldRowIndex;
    let row = info.newRowIndex;

    let outIntendNo = ed_outIntendNo.getValue();

    if (outIntendNo != '') {
        if (ds_cntrBulkOutIntendDetail.getCellData(row, "outIntendNo") != outIntendNo) {
            if (ds_cntrBulkOutIntendDetail.getCellData(row, "outIntendNo") == "") {
                gr_cntrBulkOutIntendDetail.setColumnReadOnly('choice', false);
                gr_cntrBulkOutIntendDetail.setReadOnly("grid", false);
            } else {
                gr_cntrBulkOutIntendDetail.setColumnReadOnly('choice', true);
                gr_cntrBulkOutIntendDetail.setReadOnly("grid", true);
            }
        } else {
            gr_cntrBulkOutIntendDetail.setColumnReadOnly('choice', false);
            gr_cntrBulkOutIntendDetail.setReadOnly("grid", false);
        }
    } else {
        if (ds_cntrBulkOutIntendDetail.getCellData(row, "outIntendNo") != outIntendNo) {
            if (ds_cntrBulkOutIntendDetail.getCellData(row, "outIntendNo") == "") {
                gr_cntrBulkOutIntendDetail.setColumnReadOnly('choice', false);
                gr_cntrBulkOutIntendDetail.setReadOnly("grid", false);
            } else {
                gr_cntrBulkOutIntendDetail.setColumnReadOnly('choice', true);
                gr_cntrBulkOutIntendDetail.setReadOnly("grid", true);
            }
        } else {
            gr_cntrBulkOutIntendDetail.setColumnReadOnly('choice', false);
            gr_cntrBulkOutIntendDetail.setReadOnly("grid", false);
        }
    }
    if (ds_cntrBulkOutIntend.getCellData(0, "outAdjmStsCd") != "01") {
        gr_cntrBulkOutIntendDetail.setColumnReadOnly('choice', true);
        gr_cntrBulkOutIntendDetail.setReadOnly("grid", true);
