scwin.ds_unitySelling_onrowpositionchange = function (info) {
    let oldRowIndex = info.oldRowIndex;

    let row = info.newRowIndex;
    if (row == null) {
        return;
    }

    //console.log("[onrowpositionchange] 오더매출목록 row 바뀜 :" + oldRowIndex + " -> " + row);
    //console.log("[onrowpositionchange] row status : " + ds_unitySelling.getRowStatus(row));
    //console.log("[onrowpositionchange] scwin.addYn : " + scwin.addYn);

    if (scwin.addYn == "Y") {
        ed_outIntendNo.setValue("");

        if (ds_unitySelling.getCellData(row, "outIntendNo") == "" || ds_unitySelling.getCellData(row, "dcsnClsCd") != 1) {
            gr_unitySelling.setHeaderDisabled('choice', false);
            gr_unitySelling.setColumnReadOnly('choice', false);
        } else {
            gr_unitySelling.setHeaderDisabled('choice', true);
            gr_unitySelling.setColumnReadOnly('choice', true);
        }

    }
    else {
        let outIntendNo = ds_unitySelling.getCellData(row, "outIntendNo");
        if (outIntendNo != '') {
            if (outIntendNo != ed_outIntendNo.getValue() || ds_unitySelling.getCellData(row, "dcsnClsCd") != 1) {
                gr_unitySelling.setHeaderDisabled('choice', true);
                gr_unitySelling.setHeaderValue('choice', false);
                gr_unitySelling.setColumnReadOnly('choice', true);
                gr_unitySelling.setReadOnly("grid", true);
            } else {
                gr_unitySelling.setHeaderDisabled('choice', false);
                gr_unitySelling.setColumnReadOnly('choice', false);
                gr_unitySelling.setReadOnly("grid", false);
            }
        } else {
            if (ds_unitySelling.getCellData(row, "dcsnClsCd") != 1) {
                gr_unitySelling.setHeaderDisabled('choice', true);
                gr_unitySelling.setHeaderValue('choice', false);
                gr_unitySelling.setColumnReadOnly('choice', true);
                gr_unitySelling.setReadOnly("grid", true);
            } else {
                gr_unitySelling.setHeaderDisabled('choice', false);
                gr_unitySelling.setColumnReadOnly('choice', false);
                gr_unitySelling.setReadOnly("grid", false);
            }
        }

        if (gr_unitySelling.getReadOnly("grid")) {	//readonly 일때는 다른 컬럼도 전부 readOnly 처리하고 중단.

            let colCount = ds_unitySelling.getColumnCount();
            for (let colIdx = 0; colIdx < colCount; colIdx++) {
                let colId = ds_unitySelling.getColumnID(colIdx);
                gr_unitySelling.setColumnReadOnly(colId, true);
            }
            return true;
        }

        gr_unitySelling.setHeaderDisabled('choice', false);
        //gr_unitySelling.setHeaderValue('choice', false);
        gr_unitySelling.setColumnReadOnly('choice', false);

        if (ds_unitySelling.getCellData(row, "dcScCd") != '') {
            gr_unitySelling.setColumnReadOnly('scRt', false);
        } else {
            gr_unitySelling.setColumnReadOnly('scRt', true);
        }

        //금액분할시 원본ROW edit 설정 
        if (ds_unitySelling.getCellData(row, "volAmtDivsClsCd") == "A"
            && ds_unitySelling.getCellData(row, "bilgTrgtSellSeq") == 0) {
