        } else if ((ds_unitySelling.getCellData(row, "volAmtDivsClsCd") == "A"
            && ds_unitySelling.getCellData(row, "bilgTrgtSellSeq") != 0) ||
            ds_unitySelling.getCellData(row, "volAmtDivsClsCd") == "C") {
