// Grid events
scwin.gr_cntrBulkOutIntendDetail_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (columnId == "choice") {
        if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "choice") == "T") {
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendNo", ed_outIntendNo.getValue());
            if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt") == "") {
                ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendDt", ica_outIntendDt.getValue());
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendHh") == "") {
                ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendHh", ed_outIntendHh.getValue());
            }
            if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt") != "" && ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outCrryinoutDt") != "") {
                ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "overCnt", $c.date.diffDate(ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt"), ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outCrryinoutDt")));
            }
        } else {
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendDt", "");
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "outIntendHh", "");
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "overCnt", "");
        }
        for (let i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
            scwin.f_PostSumAmt(i);
        }
    }
    if (rowIndex >= 0 && columnId == "cntrNo" && ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "cntrNo") != "") {
        scwin.f_cntrNoDetail();
    }
};

scwin.gr_unitySelling_onheaderclick = function (headerId) {

    if (headerId != "choice") {
        return;
    }

    let choiceReadOnly = gr_unitySelling.getColumnReadOnly('choice');
    let bCheck = gr_unitySelling.getHeaderValue(headerId);
    if (bCheck == true) {
        for (let i = 0; i <= ds_unitySelling.getRowCount(); i++) {
            if (choiceReadOnly == false) {
                //ds_unitySelling.setCellData(i, "choice", "T");

                if (ds_unitySelling.getCellData(i, "outIntendNo") == "") {
                    ds_unitySelling.setCellData(i, "outIntendNo", ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));
                    ds_unitySelling.setCellData(i, "outIntendSeq", ds_unitySelling.getCellData(i, "outIntendSeq"));
                }

                ds_unitySelling.setCellData(i, "sellWrkRsltsClsCd", "05");
            }
        }
    } else {
        for (let j = 0; j < ds_unitySelling.getRowCount(); j++) {
            if (choiceReadOnly == false) {
                //ds_unitySelling.setCellData(j, "choice", "F");
                ds_unitySelling.setCellData(j, "outIntendNo", "");
                ds_unitySelling.setCellData(j, "outIntendSeq", "");
                ds_unitySelling.setCellData(j, "sellWrkRsltsClsCd", "");
            }
        }
    }
    scwin.f_SumAmt();
};

scwin.gr_unitySelling_onrowindexchange = function (newRowIndex, oldRowIndex) {
};

scwin.gr_unitySelling_oncellclick = async function (rowIndex, columnIndex, columnId) {
    //console.log("오더매출목록 cell 클릭 :" + rowIndex + ", " + columnId);
    if (scwin.addYn == "Y") {
        ed_outIntendNo.setValue("");
        scwin.f_AddSumAmt();
    }
    else {
        if (columnId == "choice" && gr_unitySelling.getColumnReadOnly('choice') == false) {
            if (ds_unitySelling.getCellData(rowIndex, "choice") == "T") {
                if (ds_unitySelling.getCellData(rowIndex, "outIntendNo") == "") {
                    ds_unitySelling.setCellData(rowIndex, "outIntendNo", ds_cntrBulkOutIntend.getCellData(0, "outIntendNo"));
                    ds_unitySelling.setCellData(rowIndex, "outIntendSeq", ds_unitySelling.getCellData(rowIndex, "outIntendSeq"));
                }
                ds_unitySelling.setCellData(rowIndex, "sellWrkRsltsClsCd", "05");
            } else {
                ds_unitySelling.setCellData(rowIndex, "outIntendNo", "");
                ds_unitySelling.setCellData(rowIndex, "outIntendSeq", "");
                ds_unitySelling.setCellData(rowIndex, "sellWrkRsltsClsCd", "");
            }

            scwin.f_SumAmt();
        }

        if (columnId == "commSeq" && gr_unitySelling.getColumnReadOnly('choice') == false) {
            if (ds_unitySelling.getCellData(rowIndex, "addRowYn") == "N") {
                gr_unitySelling.setColumnReadOnly('commSeq', true);
            } else {
                gr_unitySelling.setColumnReadOnly('commSeq', false);;
            }
        }

        if (columnId == "scRt" && gr_unitySelling.getColumnReadOnly('choice') == false) {
            if (ds_unitySelling.getCellData(rowIndex, "dcScCd") == "0256" || ds_unitySelling.getCellData(rowIndex, "dcScCd") == "0257") {
                gr_unitySelling.setColumnReadOnly('scRt', false);
            } else {
                gr_unitySelling.setColumnReadOnly('scRt', true);
            }
        }

        if (columnId == "sellItemCd" && gr_unitySelling.getColumnReadOnly('choice') == false) {
            await scwin.f_RetrieveSellItem(scwin.v_bilgLodeptCd, scwin.v_fmlaClsCd, scwin.v_fmlaPatternCd);
        }
    }
};

//오더매출목록 그리드에 콤보박스 수정시
scwin.gr_unitySelling_oneditend = function (rowIndex, columnIndex, value) {

    let colid = gr_unitySelling.getColumnID(columnIndex);

    switch (colid) {
        case "sellItemCd":		//매출항목 코드 콤보박스 닫힐때
            if (rowIndex > -1) {
                scwin.gr_unitySelling_oneditend_sellItemCd(rowIndex, columnIndex, value);
            }
            break;
        case "dcScCd":			//할인할증 코드 콤보박스 닫힐때
            if (rowIndex > -1) {
                scwin.gr_unitySelling_oneditend_dcScCd(rowIndex, columnIndex, value);
            }
            break;
        case "sellUnitCd":		//적용기준 변경 
            if (rowIndex > -1) {
                scwin.f_SetSellVol(rowIndex);
            }
            break;
        case "crcCd":
            if (rowIndex > -1) {	//통화코드 콤보박스 닫힐때
                scwin.gr_unitySelling_oneditend_crcCd(rowIndex, columnIndex, value);
            }
            break;
        case "sellVol":

            break;

    }
};

// 오더매출목록 매출항목 코드 콤보박스 닫힐때
scwin.gr_unitySelling_oneditend_sellItemCd = function (rowIndex, columnIndex, value) {
    ds_unitySelling.setCellData(rowIndex, "sellUpr", 0);
    ds_unitySelling.setCellData(rowIndex, "sellVol", 0);
    ds_unitySelling.setCellData(rowIndex, "sellAmt", 0);
    ds_unitySelling.setCellData(rowIndex, "vatAmt", 0);
    ds_unitySelling.setCellData(rowIndex, "sumSellAmt", 0);

    scwin.f_AppendSellItem(ds_unitySelling.getCellData(rowIndex, "sellItemCd"), ds_unitySelling.getCellData(rowIndex, "commSeq"), 'TRUE');
};

// 오더매출목록 할인할증 코드 콤보박스 닫힐때
scwin.gr_unitySelling_oneditend_dcScCd = function (rowIndex, columnIndex, value) {

    if (value == '0257') {
        gr_unitySelling.setColumnReadOnly('scRt', false);
        if (ds_unitySelling.getCellData(rowIndex, "sellUpr") < 0) {
            ds_unitySelling.setCellData(rowIndex, "sellUpr", ds_unitySelling.getCellData(rowIndex, "sellUpr") * -1);
        }
        if (ds_unitySelling.getCellData(rowIndex, "scRt") < 0) {
            ds_unitySelling.setCellData(rowIndex, "scRt", ds_unitySelling.getCellData(rowIndex, "scRt") * -1);
        }
    } else if (value == '0256') {
        gr_unitySelling.setColumnReadOnly('scRt', false);
        if (ds_unitySelling.getCellData(rowIndex, "sellUpr") > 0) {
            ds_unitySelling.setCellData(rowIndex, "sellUpr", ds_unitySelling.getCellData(rowIndex, "sellUpr") * -1);
        }
        if (ds_unitySelling.getCellData(rowIndex, "scRt") > 0) {
            ds_unitySelling.setCellData(rowIndex, "scRt", ds_unitySelling.getCellData(rowIndex, "scRt") * -1);
        }
    } else {
        gr_unitySelling.setColumnReadOnly('scRt', true);
        if (ds_unitySelling.getCellData(rowIndex, "sellUpr") < 0) {
            ds_unitySelling.setCellData(rowIndex, "sellUpr", ds_unitySelling.getCellData(rowIndex, "sellUpr") * -1);
        }
        if (ds_unitySelling.getCellData(rowIndex, "scRt") < 0) {
            ds_unitySelling.setCellData(rowIndex, "scRt", ds_unitySelling.getCellData(rowIndex, "scRt") * -1);
        }
    }

    ds_unitySelling.setCellData(rowIndex, "sellAmt", ds_unitySelling.getCellData(rowIndex, "sellUpr") * ds_unitySelling.getCellData(rowIndex, "sellVol"));
    if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
        ds_unitySelling.setCellData(rowIndex, "vatAmt", Math.round(ds_unitySelling.getCellData(rowIndex, "sellAmt") * 0.1));
    } else {
        ds_unitySelling.setCellData(rowIndex, "vatAmt", 0);
    }
    ds_unitySelling.setCellData(rowIndex, "sumSellAmt", Number(ds_unitySelling.getCellData(rowIndex, "sellAmt")) + Number(ds_unitySelling.getCellData(rowIndex, "vatAmt")));

};

