        }
        ds_unitySelling.setCellData(rowIndex, "sumSellAmt", Number(ds_unitySelling.getCellData(rowIndex, "sellAmt")) + Number(ds_unitySelling.getCellData(rowIndex, "vatAmt")));
    }
};

// 오더매출목록 데이터 변경시
scwin.ds_unitySelling_oncelldatachange = function (info) {
    let oldValue = info.oldValue;
    let newValue = info.newValue;

    if (oldValue == newValue) {
        return;
    }

    let rowIndex = info.rowIndex;
    let colID = info.colID;

    //console.log("오더매출목록 데이터 변경 rowIndex : " + rowIndex + ", colID " + colID + ", data : " + oldValue + " -> " + newValue);

    switch (colID) {
        case "sellVol":	//매출물량 변경시
            scwin.ds_unitySelling_oncelldatachange_sellVol(rowIndex);
            break;
        case "sellUpr":	//단가
            scwin.ds_unitySelling_oncelldatachange_sellUpr(rowIndex, oldValue);
            break;
        case "scRt": 	//할인할증률
            scwin.ds_unitySelling_oncelldatachange_scRt(rowIndex);
            break;
        case "sellAmt": 	//공급가액
            scwin.ds_unitySelling_oncelldatachange_sellAmt(rowIndex, oldValue);
            break;
        case "vatAmt": 	//부가세
            ds_unitySelling.setCellData(rowIndex, "sumSellAmt",
                (Number(ds_unitySelling.getCellData(rowIndex, "sellAmt")) + Number(ds_unitySelling.getCellData(rowIndex, "vatAmt")))
            );
            break;
        case "commSeq": 	//순번
            scwin.ds_unitySelling_oncelldatachange_commSeq(rowIndex);
            break;
        case "adptExchRt": 	//환율
            scwin.ds_unitySelling_oncelldatachange_adptExchRt(rowIndex);
            break;
        default:
            return;
    }

    scwin.f_SumAmt();
};

// 오더매출목록 매출물량 변경시
scwin.ds_unitySelling_oncelldatachange_sellVol = function (row) {

    if (ds_unitySelling.getCellData(row, "sellItemCd") == "0003" ||
        ds_unitySelling.getCellData(row, "sellItemCd") == "0009" ||
        ds_unitySelling.getCellData(row, "sellItemCd") == "0008") {
        sellItemGubun = "ONE";
        scwin.f_retrieveBulkSellingItem(row, ds_unitySelling.getCellData(row, "sellVol"));
    }

    //공급가액,부가세,금액 계산
    ds_unitySelling.setCellData(row, "sellAmt", ds_unitySelling.getCellData(row, "sellUpr") * ds_unitySelling.getCellData(row, "sellVol"));
    if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
        ds_unitySelling.setCellData(row, "vatAmt", Math.round(ds_unitySelling.getCellData(row, "sellAmt") * 0.1));
    } else {
        ds_unitySelling.setCellData(row, "vatAmt", 0);
    }
    ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));
};

// 오더매출목록 단가 변경시
scwin.ds_unitySelling_oncelldatachange_sellUpr = function (row, olddata) {
    //단가 계산
    if (ds_unitySelling.getCellData(row, "dcScCd") == '0256') {
        if (ds_unitySelling.getCellData(row, "sellUpr") > 0) {
            ds_unitySelling.setCellData(row, "sellUpr", ds_unitySelling.getCellData(row, "sellUpr") * -1);
        }
    } else {
        if (ds_unitySelling.getCellData(row, "sellUpr") < 0) {
            ds_unitySelling.setCellData(row, "sellUpr", ds_unitySelling.getCellData(row, "sellUpr") * -1);
        }
    }

    //금액분할시 세팅
    if (ds_unitySelling.getCellData(row, "volAmtDivsClsCd") == "A" || ds_unitySelling.getCellData(row, "volAmtDivsClsCd") == "C") {
        var P_sellUpr = ds_unitySelling.getCellData(scwin.fitRow, "sellUpr");
        var C_orgSellUpr = ds_unitySelling.getCellData(row, "sellUpr") - olddata;
        //원본Row 보다 단가가 클경우
        if (C_orgSellUpr > P_sellUpr) {
            $c.win.alert("분할 금액이 원본 금액을 초과할수 없습니다.");
            ds_unitySelling.setCellData(row, "sellUpr", olddata);
            return;
        }

        //원본Row 보다 단가가 클경우
        var orgSellUpr = ds_unitySelling.getOriginalCellData(scwin.fitRow, "sellUpr");
        if (ds_unitySelling.getCellData(row, "volAmtDivsClsCd") == "A" && ds_unitySelling.getCellData(row, "bilgTrgtOdrNo") != "") {
            orgSellUpr = ds_unitySelling.getCellData(scwin.fitRow, "sellUpr") + olddata;
        }

        if (ds_unitySelling.getCellData(row, "sellUpr") <= orgSellUpr) {
            ds_unitySelling.setCellData(scwin.fitRow, "sellUpr", orgSellUpr - ds_unitySelling.getCellData(row, "sellUpr"));
            ds_unitySelling.setCellData(scwin.fitRow, "sellAmt", ds_unitySelling.getCellData(scwin.fitRow, "sellUpr") * ds_unitySelling.getCellData(scwin.fitRow, "sellVol"));
            ds_unitySelling.setCellData(row, "sellAmt", ds_unitySelling.getCellData(row, "sellUpr") * ds_unitySelling.getCellData(row, "sellVol"));

            //원본 ROW 공급가액,부가세,금액 계산
            if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
                ds_unitySelling.setCellData(scwin.fitRow, "vatAmt", Math.round(ds_unitySelling.getCellData(scwin.fitRow, "sellAmt") * 0.1));
            } else {
                ds_unitySelling.setCellData(scwin.fitRow, "vatAmt", 0);
            }
            ds_unitySelling.setCellData(scwin.fitRow, "sumSellAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "sellAmt")) + Number(ds_unitySelling.getCellData(scwin.fitRow, "vatAmt")));

            //분할 ROW 공급가액,부가세,금액 계산
            if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
                ds_unitySelling.setCellData(row, "vatAmt", Math.round(ds_unitySelling.getCellData(row, "sellAmt") * 0.1));
            } else {
                ds_unitySelling.setCellData(row, "vatAmt", 0);
            }
            ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));
        }
    } else {
        //공급가액,부가세,금액 계산
        ds_unitySelling.setCellData(row, "sellAmt", ds_unitySelling.getCellData(row, "sellUpr") * ds_unitySelling.getCellData(row, "sellVol"));
        if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
            ds_unitySelling.setCellData(row, "vatAmt", Math.round(ds_unitySelling.getCellData(row, "sellAmt") * 0.1));
        } else {
            ds_unitySelling.setCellData(row, "vatAmt", 0);
        }
        ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));

    }
};

// 오더매출목록 할인할증률 변경시
scwin.ds_unitySelling_oncelldatachange_scRt = function (row) {
    ds_unitySelling.setCellData(row, "sellUpr", ds_unitySelling.getCellData(row, "sellUpr") * (ds_unitySelling.getCellData(row, "scRt") / 100));

    ds_unitySelling.setCellData(row, "sellAmt", ds_unitySelling.getCellData(row, "sellUpr") * ds_unitySelling.getCellData(row, "sellVol"));
    if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
        ds_unitySelling.setCellData(row, "vatAmt", Math.round(ds_unitySelling.getCellData(row, "sellAmt") * 0.1));
    } else {
        ds_unitySelling.setCellData(row, "vatAmt", 0);
    }
    ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));

    if (ds_unitySelling.getCellData(row, "dcScCd") == '0256') {
        if (ds_unitySelling.getCellData(row, "scRt") > 0) {
            ds_unitySelling.setCellData(row, "scRt", ds_unitySelling.getCellData(row, "scRt") * -1);
        }
    } else {
        if (ds_unitySelling.getCellData(row, "scRt") < 0) {
            ds_unitySelling.setCellData(row, "scRt", ds_unitySelling.getCellData(row, "scRt") * -1);
        }
    }
};

