            ds_unitySelling.setCellData(scwin.fitRow, "sellUpr", ds_unitySelling.getCellData(scwin.fitRow, "sellAmt") / ds_unitySelling.getCellData(scwin.fitRow, "sellVol"));
            ds_unitySelling.setCellData(row, "sellUpr", ds_unitySelling.getCellData(row, "sellAmt") / ds_unitySelling.getCellData(row, "sellVol"));

            //원본 ROW 공급가액,부가세,금액 계산
            if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
                ds_unitySelling.setCellData(scwin.fitRow, "vatAmt", Math.round(ds_unitySelling.getCellData(scwin.fitRow, "sellAmt") * 0.1));
            } else {
                ds_unitySelling.setCellData(scwin.fitRow, "vatAmt", 0);
            }
            ds_unitySelling.setCellData(scwin.fitRow, "sumSellAmt", Number(ds_unitySelling.getCellData(scwin.fitRow, "sellAmt")) + Number(ds_unitySelling.getCellData(scwin.fitRow, "vatAmt")));

            //분할 ROW 공급가액,부가세,금액 계산
            if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
                ds_unitySelling.setCellData(row, "vatAmt", Math.round(ds_unitySelling.getCellData(row, "sellAmt") * 0.1));
            } else {
                ds_unitySelling.setCellData(row, "vatAmt", 0);
            }
            ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));
        }
    } else {
        if (ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "01" || ds_cntrBulkOutIntend.getCellData(0, "taxnClsCd") == "04") {
            ds_unitySelling.setCellData(row, "vatAmt", Math.round(ds_unitySelling.getCellData(row, "sellAmt") * 0.1));
        } else {
            ds_unitySelling.setCellData(row, "vatAmt", 0);
        }
        ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));
    }
};

// 오더매출목록 순번 변경시
scwin.ds_unitySelling_oncelldatachange_commSeq = function (row) {
    let isCntr = true;
    for (var i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
        if (ds_cntrBulkOutIntendDetail.getCellData(i, "commSeq") != ds_unitySelling.getCellData(row, "commSeq")) {
            isCntr = false;
        } else {
            ds_unitySelling.setCellData(row, "sellCommNo", ds_cntrBulkOutIntendDetail.getCellData(i, "cntrNo"));
            isCntr = true;
            break;
        }
    }

    if (isCntr == true && ds_unitySelling.getCellData(row, "sellUnitCd") != '') {
        //매출물량 세팅
        scwin.f_SetSellVol(row);
    }
};

// 오더매출목록 환율 변경시
scwin.ds_unitySelling_oncelldatachange_adptExchRt = function (row) {
    ds_unitySelling.setCellData(row, "sellAmt", ds_unitySelling.getCellData(row, "sellAmtFcrc") * ds_unitySelling.getCellData(row, "adptExchRt"));
    ds_unitySelling.setCellData(row, "vatAmt", 0);
    ds_unitySelling.setCellData(row, "sumSellAmt", Number(ds_unitySelling.getCellData(row, "sellAmt")) + Number(ds_unitySelling.getCellData(row, "vatAmt")));
};

// 출고예정일자 콤보박스 닫힐때
scwin.gr_cntrBulkOutIntendDetail_oneditend = function (rowIndex, columnIndex, value) {
    let colID = gr_cntrBulkOutIntendDetail.getColumnID(columnIndex);

    if (colID == "outIntendDt") {
        if (ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt") != "" && ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outCrryinoutDt") != "") {
            let count = WebSquare.date.dateDiff(ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outIntendDt"), ds_cntrBulkOutIntendDetail.getCellData(rowIndex, "outCrryinoutDt"));
            ds_cntrBulkOutIntendDetail.setCellData(rowIndex, "overCnt", count);
        }
    }
};

//gr_cntrBulkOutIntendDetail - OnHeadCheckClick
scwin.gr_cntrBulkOutIntendDetail_onheaderclick = function (headerId) {

    if (headerId != "choice")
        return;

    let choceReadOnly = gr_cntrBulkOutIntendDetail.getColumnReadOnly('choice');
    let bCheck = gr_cntrBulkOutIntendDetail.getHeaderValue(headerId);

    if (bCheck == true) {

        for (var i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
            if (choceReadOnly == false) {
                ds_cntrBulkOutIntendDetail.setCellData(i, "choice", "T");
                ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendNo", ed_outIntendNo.getValue());

                if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") == "") {
                    ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendDt", ica_outIntendDt.getValue());
                }

                if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendHh") == "") {
                    ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendHh", ed_outIntendHh.getValue());
                }

                if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") != "" && ds_cntrBulkOutIntendDetail.getCellData(i, "outCrryinoutDt") != "") {
                    let count = WebSquare.date.dateDiff(ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt"), ds_cntrBulkOutIntendDetail.getCellData(i, "outCrryinoutDt"));
                    ds_cntrBulkOutIntendDetail.setCellData(i, "overCnt", count);
                }

                scwin.f_PostSumAmt(i);
            }
        }
    } else {
        for (var i = 0; i < ds_cntrBulkOutIntendDetail.getRowCount(); i++) {
            if (choceReadOnly == false) {
                ds_cntrBulkOutIntendDetail.setCellData(i, "choice", "F");
                ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendNo", "");
                ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendDt", "");
                ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendHh", "");
                ds_cntrBulkOutIntendDetail.setCellData(i, "overCnt", "");
            }
        }
    }
};

