scwin.cfConvert2Weight = function (value, fromUnit, toUnit) {
    let val = value;

    if (fromUnit === "KG" && toUnit === "TON") {
        val = value / 1000;
    } else if (fromUnit === "TON" && toUnit === "KG") {
        val = value * 1000;
    }

    return Number(val.toFixed(0));
};

