// 실적기준일자 포커스아웃
scwin.ica_rsltsStdDt_onblur = function (e) {
    let rsltsStdDt = ica_rsltsStdDt.getValue();
    const cnt = ds_unitySelling.getRowCount();

    for (let i = 1; i <= cnt; i++) {
        if (ds_unitySelling.getCellData(i, "choice") != "T") {
            continue;
        }

        ds_unitySelling.setCellData(i, "rsltsStdDt", rsltsStdDt);
        ds_unitySelling.setCellData(i, "wrkStDt", rsltsStdDt);
    }
};

// 출고예정일시 포커스아웃
scwin.ica_outIntendDt_onblur = function (e) {
    let outIntendDt = ica_outIntendDt.getValue();
    const cnt = ds_cntrBulkOutIntendDetail.getRowCount();

    for (var i = 1; i <= cnt; i++) {
        if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendDt") == "") {
                ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendDt", outIntendDt);
            }
        }
    }
};
scwin.ed_outIntendHh_onblur = function (e) {
    let outIntendHh = ed_outIntendHh.getValue();
    const cnt = ds_cntrBulkOutIntendDetail.getRowCount();

    for (var i = 1; i <= cnt; i++) {
        if (ds_cntrBulkOutIntendDetail.getCellData(i, "choice") == "T") {
            if (ds_cntrBulkOutIntendDetail.getCellData(i, "outIntendHh") == "") {
                ds_cntrBulkOutIntendDetail.setCellData(i, "outIntendHh", outIntendHh);
            }
        }
    }
};

//출고청구유형 변경시
scwin.acb_fmlaPatternCd_onchange = function (info) {
    let fmlaPatternCd = acb_fmlaPatternCd.getValue();
    scwin.v_fmlaClsCd = fmlaPatternCd.substring(0, 2);
    scwin.v_fmlaPatternCd = fmlaPatternCd.substring(2, 4);
};

//출고정산유형 변경
scwin.acb_outAdjmPatternCd_onchange = function (info) {
    scwin.f_ChgoutAdjmPatternCd();
};

//선청구구분 변경
scwin.rd_prebilgClsCd_onchange = function (info) {
    scwin.f_ChgprebilgClsCd();
    scwin.f_ChgoutAdjmPatternCd();

    if (rd_prebilgClsCd.getValue() == "01") {	//선청구
        //선청구일 경우 출고청구유형을 변경 가능하게
        ed_fmlaPatternNm.hide();
        acb_fmlaPatternCd.show();

        if (ed_outIntendNo.getValue() != '') {	//출고예정번호가 있을 경우
            acb_fmlaPatternCd.setReadOnly(true);	//출고청구유형 변경 불가능하게
        } else {
            acb_fmlaPatternCd.setReadOnly(false);
        }
    } else {
        //영수일 경우 출고청구유형을 변경 불가능하게
        ed_fmlaPatternNm.show();
        acb_fmlaPatternCd.hide();
    }
};

